        THE_HALLOWED_HALLS_OF_YOUR_HOUSE_ARE_EVEN                                 = 7104,  -- The hallowed halls of your house are even more exciting! Why? Because now there's a second floor, kupo!
        BUT_BEFORE_YOU_BASH_YOUR_WAY_IN_I                                         = 7105,  -- But before you bash your way in, I've got a trifling task for you to tackle.
        CAPRICIOUS_MITHRA_CUBS_HAVE_CAJOLED_CRITICAL_INFORMATION_OUT              = 7106,  -- Capricious Mithra cubs have cajoled critical information out of the M.H.M.U., and I want you to wrest it from them!
        VISIT_THE_THREE_NATIONS_AND_QUESTION_THEM_KUPO                            = 7107,  -- Visit the three nations and question them, kupo!
        NOW_YOU_KNOW_THE_NITTY_GRITTY_SO_ENJOY                                    = 7108,  -- Now you know the nitty-gritty, so enjoy your new floor, kupo!
        KUPOPO_YOU_MEAN_YOU_ALREADY_KNOW                                          = 7109,  -- Kupopo? You mean you already know?
