        BUT_ONLY_ON_THE_SECOND_FLOOR_KUPO_I                                       = 7114,  -- But only on the second floor, kupo. I like the first floor as it is.
        AND_AS_FOR_YOUR_POTTED_PLANTS_THEY_ONLY                                   = 7115,  -- And as for your potted plants--they only persevere on the ground, kupo.
        AND_MOGHANCEMENT_EFFECTS_ONLY_ACTIVATE_FOR_FURNISHINGS_FITTED             = 7116,  -- And moghancement effects only activate for furnishings fitted to the first floor.
