        MIGHT_BRING_A_CERTAIN_JE_NE_SAIS_QUOI                                     = 7120,  -- % might bring a certain je ne sais quoi to your Mog House, kupo!
        AH_I_NEVER_THOUGHT_THAT_THIS_DAY_WOULD                                    = 7121,  -- Ah, I never thought that this day would come, kupo...
        INDEED_IT_SEEMS_LIKE_JUST_YESTERDAY_THAT_WE                               = 7122,  -- Indeed, it seems like just yesterday that we first met here.
        I_HAVE_WATCHED_WITH_WONDER_AS_YOU_GREW                                    = 7123,  -- I have watched with wonder as you grew before my very eyes, kupo.
        IN_FACT_I_HEARD_MANY_TALES_OF_YOUR                                        = 7124,  -- In fact, I heard many tales of your boundless bravery from my friends across the world.
