        IF_IT_ISN_T_WORRRTH_MUCH_THEN_SELL                                        = 7635,  -- If it isn't worrrth much, then sell it to the Goldsmiths' Guild. Just be sure you bring the proceeds from the sale back to me, okay?
        SO_DID_YOU_MAKE_IT_TO_THE_GOLDSMITHS                                      = 7636,  -- So, did you make it to the Goldsmiths' Guild in Bastok? Good for you! And how much did you get for that lump of rrrock?
        OH_YOU_DIDN_T_SELL_IT_WELL_GO                                             = 7637,  -- Oh...You didn't sell it? Well, go back to Bastok and sell it, then. Now, get going!
        WELL_IF_WE_VE_ONLY_LEARNED_ONE_THING                                      = 7638,  -- Well, if we've only learned one thing, it's this--it's farrr better to set our sights on the travelers in the port area.
        THE_TRAVELERS_IN_WINDURST_WOODS_ARE_ALL_MERCHANTS                         = 7639,  -- The travelers in Windurst Woods are all merchants who keep their guard up, or the occasional idiot who carries around a strange rock as if it's a precious jewel. Not worth the efforrrt, is it?
        SEEMS_THE_TOP_CAT_HERRRSELF_CAN_MAKE_MISTAKES                             = 7640,  -- Seems the top cat herrrself can make mistakes sometimes. Picking pebbles from the pockets of passers-by... My ass-onance! She's got me talking-walking like a Tarutaru now!
        OOPS_KEEP_WHAT_I_SAID_JUST_NOW_A                                          = 7641,  -- Oops...! Keep what I said just now a secret, okay? Parrrticularly keep it from the top cat!
