        GRRR_IF_YOU_HADN_T_SOLD_IT_OFF                                            = 7643,  -- Grrr... If you hadn't sold it off, we could have received a bigger reward from that silly traveler for finding it... Oh well... It's no longer worth my bother.
        AHHH_I_TRAVELED_ALL_THE_WAY_HERE_FROM                                     = 7644,  -- Ahhh... I traveled all the way here from Bastok, but I lost the stone that was the purpose of my journey.
