        I_D_PREFER_TO_GIVE_YOU_THE_WORK                                           = 7675,  -- I'd prefer to give you the work we find the most trying, such as the more delicate missions. Then again, any task involving Tarutaru is delicate in our opinion...
        THIS_IS_THE_EASTERRRN_GATEHOUSE_FEEL_FREE_TO                              = 7676,  -- This is the easterrrn gatehouse. Feel free to ask Captain Rakoh Buuma whenever you need a helping paw from Buuma's Boomerrrs! She's the grrreatest!
        THE_THE_MITHRA_LADIES_ARE_NORMALLY_VERY_P                                 = 7677,  -- The, the Mithra ladies are normally very p-pleasant and ch-cheery, but you've got to keep on your toesy-woesies!
        ONCE_I_ERM_NODDED_OFF_FOR_A_BIT                                           = 7678,  -- Once, I, erm, nodded off for a bit, and, and, woke up to find bite marks on my leggy-leg-legs! I, I, erm, don't want to be eatened!!!
        THAT_MEERI_WOHRI_IS_A_CLUMSY_LITTLE_NERRRVOUS                             = 7679,  -- That Meeri-Wohri is a clumsy little nerrrvous wreck, y'know?
        ONE_DAY_I_AWOKE_FROM_A_CAT_NAP                                            = 7680,  -- One day, I awoke from a cat nap wherrre I was having this dream about eating a Mithkabob, only to find I was chewing on the little guy's leg! I hope I didn't hurrrt him...to`o much.
        THIS_IS_THE_EASTERN_GATEHOUSE_A_GATHERING_PLACE_2                         = 7681,  -- This is the eastern gatehouse--a gathering place for the guards who do the rrrounds of Windurst Woods.
        TO_EXPEL_THOSE_WHO_WOULD_SUBVERT_THE_LAW                                  = 7682,  -- To expel those who would subvert the law and order of Windurst Woods... To protect the Mithra populace from all manner of threats and dangers... That is the job of us guards.
        BUT_LATELY_FEROCIOUS_MONSTERS_ARE_ON_THE_INCREASE                         = 7683,  -- But lately, ferocious monsters are on the increase, and the beastmen are rrruining nature as they please, so our job is becoming all the more hectic.
        IF_YOU_ARE_A_CITIZEN_OF_WINDURST_THEN                                     = 7684,  -- If you are a citizen of Windurst, then perhaps you may lend us a helping hand from time to time in order to protect the peace of our fair town.
        FOR_INSTANCE_YOU_COULD_TRY_TO_DO_SOME                                     = 7685,  -- For instance, you could try to do some missions...special tasks issued on behalf of the Federation of Windurst...
        BUT_FIRST_YOU_MIGHT_PREFER_TO_LISTEN_TO                                   = 7686,  -- But first, you might prefer to listen to our explanation of the rrrole of gatehouses before you decide...
        HEAR_EXPLANATION_OF_GATEHOUSES_HEAR_HEAR_TURN_A                           = 7687,  -- Hear explanation of gatehouses? Hear! Hear! Turn a deaf ear.
        GOOD_THEN_ALLOW_US_TO_EXPLAIN_SOLA_JAAB                                   = 7688,  -- Good, then allow us to explain. Sola Jaab, would you like to do the honors?
        ROGER_CAPTAIN_BUUMA_IT_WOULD_INDEED_BE_AN                                 = 7689,  -- Roger, Captain Buuma! It would indeed be an honorrr...
        WELL_PUT_SIMPLY_THE_GATEHOUSES_ARE_WHERE_WE                               = 7690,  -- Well, put simply, the gatehouses are where we guards worrrk and rest.
