        WELL_SAID_THAT_HEARTFELT_RRREPLY_IS_YOUR_FIRST                            = 7699,  -- Well said! That heartfelt rrreply is your first great step towards making Windurst a better place.
        SO_WITHOUT_FURTHER_DELAY_LET_S_ISSUE_YOU                                  = 7700,  -- So, without further delay, let's issue you your first mission. Do either of you have just the rrright mission for him/her]?
        SAID_LIKE_A_REAL_WOMAN_THAT_HEARTFELT_REPLY                               = 7701,  -- Said like a real woman! That heartfelt reply is your first great step towards making Windurst a better place.
        SO_WITHOUT_FURTHER_DELAY_LET_S_ISSUE_YOU_2                                = 7702,  -- So, without further delay, let's issue you with your first mission. Do either of you have just the rrright mission for our sister here?
        EX_EXCUSEY_ME_BUT_I_ERM_I_KNOW                                            = 7703,  -- Ex...excusey me... But, I, erm, I know of a mission-wission...
