        DID_YOU_ENJOY_YOUR_LITTLE_RUN_IN_WITH                                     = 7718,  -- Did you enjoy your little run-in with the ministerrr of the Orastery? Grrr... Oh, and were you able to meet his little sisterrr?
        THE_MINISTER_OF_THE_ORASTERY_S_SISTERRR_IS                                = 7719,  -- The Minister of the Orastery's sisterrr is named Apururu. You'd know if you met herrr. She's also the ministerrr of the Manustery.
        MISSIONS_ARE_ALL_VERRRY_WELL_AND_GOOD_BUT                                 = 7720,  -- Missions are all verrry well and good, but you should also try some quests too...I think!
        SPEAKING_TO_THE_TOWNSFOLK_AND_TRRRYING_TO_HELP                            = 7721,  -- Speaking to the townsfolk and trrrying to help them with their problems... It can be very beneficial, y'know!
        YOU_VE_COME_JUST_AT_THE_RRRIGHT_TIME                                      = 7722,  -- You've come just at the rrright time. The Manustery just up the rrroad there is asking for help in making automaton guards at the Cardian workshop.
