        MITHRA_ARE_PURRRETTY_GOOD_WITH_THEIR_HANDS_YOU                            = 8023,  -- Mithra are purrretty good with their hands, you know? Why, we even give the Tarutaru a rrrun for their money! That's why there are so many guild buildings in Windurrrst Woods.
        BY_THE_WAY_UP_THIS_PATH_YOU_CAN                                           = 8024,  -- By the way, up this path, you can see the Weaverrrs' Guild. Behind the Weavers' Guild is the Boneworkerrrs' Guild.
        IF_YOU_CAN_T_FIND_WHAT_YOU_WANT                                           = 8025,  -- If you can't find what you want at Nchaa's Good Goods shop up therrre, then try heading over to street stalls in the Bomingo Round.
        YOU_MIGHT_EXPERIENCE_SOME_SERENDIPITY_THERRRE_THERE_S                     = 8026,  -- You might experience some serendipity therrre. There's one guy at the local restaurant who claims he always makes grrreat finds at those stalls.
        WE_MITHRA_MAY_LIVE_FREELY_BUT_WE_KNOW                                     = 8027,  -- We Mithra may live freely, but we know rrright from wrrrong.
        THAT_CAT_BURGLAR_NANAA_MIHGO_MAY_THINK_SHE                                = 8028,  -- That Cat Burglar, Nanaa Mihgo, may think she has everyone fooled with that cute act of hers, but a crrrook is a crrrook! Don't let yourself be taken in by herrr or herrr gang!
        WOULD_YOU_SHUT_THIS_LITTLE_CUB_UP_FOR                                     = 8029,  -- Would you shut this little cub up for me? She is too pesky and noisy forrr her own good!
        THE_SIBYL_GUARDS_ARE_NOT_REAL_MITHRA_BECAUSE                              = 8030,  -- The Sibyl Guards are not real Mithra because they werrre raised by Tarutaru! I don't carrre how strong they are. They've lost the Mithra spirrrit.
        CRAFT_SKILLS_REQUIRE_YOU_TO_PRACTICE_OVERRR_AND                           = 8031,  -- Craft skills require you to practice overrr and overrr, wasting many items, until you learn how to synthesize and create things properrrly.
        BUT_WHEN_YOU_FINALLY_CAN_CREATE_WEAPONS_AND                               = 8032,  -- But when you finally can create weapons and other cool stuff that aren't found at the shops, then it finally becomes worrrth all that efforrrt. At the very least, you can show off to your frrriends!
        DEFINITIONF_EQUIPMENT_SOME_THING_THATNE_EQUIPS                            = 8033,  -- defInitionf Equipment: Some-tHing ThatNe eQuIps!
        DO_YOUAVE_YOUR_EQUIPMENTROPERLY_EQUIPPED_EMEMBER_HERE_IS                  = 8034,  -- dO yOuaVe yOUr eQuipMentroPerly equiPped!?eMemBer:here is AoRRect plAce fOrveryThing!
        DEFINITIONF_FOOL_HARDYDVENTURER_NE_WHOANDOMLY_FIGHTSNY_THING              = 8035,  -- dEfInItIOnf fOOl-hArdydvEntUrEr:nE whOAndOmly fIghtsny-thIng!
        LEARNOW_TOELL_THEELATIVE_STRENGTHSF_MONSTERS_HE_CHECKOMMAND_ISHE          = 8036,  -- lEArnOw tOEll thEElAtIvE strEngthsf mOnstErs!hE CHECKOmmAnd IshE kEyO vIctOry!
        OTHERIDE_OFHIS_BUILDINGS_WINDURSTESI_DENTIAL_AREA                         = 8037,  -- oThErIdE oFhIs bUiLdIngS WiNdUrStEsI-dEnTiAl ArEa!
        ASKBBY_JALUNSHIOR_EXPLAN_ATIONS                                           = 8038,  -- AsKBBy JaLunShiOr ExPlAn-AtIoNs!
        WHENRAVEL_ING_LONGISTANCES_CHOCOBOSAN_EASE_YOUROURNEY                     = 8039,  -- WhEnRAvel-INg lONgIStANcEs, CHoCoBOsAn eAse yOurOUrney!
        BUT_ONEEEDS_TOULFILL_MANYEQUIRE_MENTS_BEFORENE_CANIDE_CHOCOBOS            = 8040,  -- bUt oNeEEds tOUlfIll mANyEqUIre-mENts bEfOreNe cAnIDe chOcObOs!
        CAR_DIANSOTOTH_ERED_BYAINR_WIND_UTIGHT_NINGOR_RIES                        = 8041,  -- CaR-DiAnSOtOtH-ErEd bYAiNR wInD!uTiGht-NInGOr-RiEs US...aIt-tLe!
        THREEILLA_TROLTREETSORO_TECTEACEFIN_DURST                                 = 8042,  -- tHrEeIlLA-tRoLtReEtSOrO-tECtEAcEfIn-DuRst!
        TWON_ABLEOE_MOR_IZEIN_DURSTOODSET_TWOAIL_URESAR_DIAN                      = 8043,  -- TwON-AblEoe-MoR-IZeiN-dURsToOdSEt! TWoaIl-UrESaR-dIaN!
        ONE_MORE_TIME                                                             = 8044,  -- One more time...
        THE_RAIN_IN_LA_THEINE_FALLS_MAINLY_ON                                     = 8045,  -- The rain in La Theine falls mainly on the plains.
        TO_PROTECT_THE_FUTURE_OF_OUR_CHILDREN_WE                                  = 8046,  -- To protect the future of our children, we adults must give first priority to the maintenance of peace.
        IT_IS_FOR_THIS_VERY_REASON_THAT_THE                                       = 8047,  -- It is for this very reason that the great Star Sibyl, in her infinite wisdom, made a peace accord with the Yagudo beastmen.
        SIXUST_BITIX_S_TONGUE_OUCH_TONGUEURTS                                     = 8048,  -- sIxUsT bItIX's ToNGuE! OuCH! tOnGuEURtS!
        BUTANARDIANS_FEELAIN_MAYBE_ITS_SIX_SMAGINATION_BUT_CANARDIANSMAGINE       = 8049,  -- ...BuTAnArDIaNs fEElAiN? MaYbE iTS SIx'SmAgInAtIoN? ...bUt CaNaRdiAnSmAgInE?
        HI_DIDDLY_DIDDLY_I_AM_APURURU_THE_CURRENT                                 = 8050,  -- Hi-diddly-diddly! I am Apururu, the current minister of this Manustery and its Cardian workshop. Nice to meetaru!
        THIS_IS_WHERE_WE_BREATHE_LIFE_INTO_THE                                    = 8051,  -- This is where we breathe life into the automaton guards that we call Cardians.
        YOU_ARE_FREE_TO_LOOK_AROUND_BUT_WE                                        = 8052,  -- You are free to look around, but we ask that you don't go teaching strange things to our newly created Cardians!
        THE_WAY_YOU_RE_WALKING_AROUND_HERE_I                                      = 8053,  -- The way you're walking around here, I'd swear you think that this ministry is an unusual sight.
        HM_YOU_THINK_OUR_CARDIANS_ARE_ODD_WELL                                    = 8054,  -- Hm? You think our Cardians are odd? Well, I'd say you're the odd one around herey-werey!
        THIS_IS_THE_MANUSTERY_THE_MINISTRY_THAT_S                                 = 8055,  -- This is the Manustery--the ministry that's in charge of making and maintaining Cardians. Most people just refer to us as the Cardian workshop.
        THE_AUTOMATON_GUARDS_YOU_SEE_WORKING_ALL_OVER                             = 8056,  -- The automaton guards you see working all over Windurst are born and raised by us here. Don'taru think it's kind of amazing, kid?
        I_M_STILL_NEWY_AROUND_HERE_SO_THEY                                        = 8057,  -- I'm still newy around here, so they won't let me helpy out in creating Cardians yet.
        BUT_I_SO_WANT_TO_HURRY_UP_AND                                             = 8058,  -- But I so want to hurry up and test my strengthy. I bet I can make a really-weally strong Cardian!
        ONE_SREE_TINGS                                                            = 8059,  -- ONE'SREE-TINGS... ?
        TWOSAR_DI_AN_YOUSEO_PLE                                                   = 8060,  -- TWOSAR-DI-AN! YOUSEO-PLE!
        ONEEDP_PLELUSNELUEP_PLEAKES_ONEUR_PLEP_PLE                                = 8061,  -- ONEEDP-PLELUSNELUEP-PLEAKES......ONEUR-PLEP-PLE!?
        CUR_RENTO_CA_TION_FED_ER_A_TIONFIN                                        = 8062,  -- CUR-RENTO-CA-TION: FED-ER-A-TIONFIN-DURST...INARUTA-BARUTAE-GION...ONON-TI-NENTFIN-DAR-TIA...VA-NA'DIEL...!
        THE_R_RAINNAHEINEALLS_M_MAIN_LYNHE_P_PLAINS                               = 8063,  -- THE-R-RAINNAHEINEALLS-M-MAIN-LYNHE-P-PLAINS!
        I_CANNOT_READ_ITS_MODEL_NUMBER_BUT_THIS                                   = 8064,  -- I cannot read its model number, but this is one of our children who left our ministry and died somewhere out there...
        I_THINK_IT_MUST_HAVE_BEEN_QUITE_LONELY                                    = 8065,  -- I think it must have been quite lonely-wonely... Oh, but thank you for bringing this back to us!
        I_HEARD_ABOUT_YOU_ADVENTURER_IT_SEEMS_THAT                                = 8066,  -- I heard about you, adventurer! It seems that you turned out to be quite the hero...
        THANK_YOU_FOR_SAVING_WINDURST_NO_FOR_SAVING                               = 8067,  -- Thank you for saving Windurst...no...for saving our whole world!
        BY_THE_WAY_YOU_DIDN_TARU_HAPPEN_TO                                        = 8068,  -- By the way...you didn'taru happen to bump into my big brother, Ajido-Marujido, along the way, did you? He dashed out of Windurst by himself, saying, The time is ripe! You should come along too!
        I_NO_LONGER_CARE_WHAT_HAPPENS_TO_HIM                                      = 8069,  -- I no longer care what happens to him. So, if by any chance you do meet up with him, tell him I said he can carry out his crooked-wooked schemey-whemies all by himselfy-welfy! Humph!
        WHY_HELLO_THERE_FRIEND_STEP_RIGHT_UP_HERE                                 = 8070,  -- Why, hello there, friend! Step right up here and tell me this--are you satisfied with our current Cardians?
        SATISFIED_WITH_CARDIANS_NO_NOT_QUITE_YES_MOST                             = 8071,  -- Satisfied with Cardians? No, not quite... Yes, most sufficient.
        GEE_YOU_DON_T_HAVE_TO_BE_SUCH                                             = 8072,  -- Gee... You don't have to be such a wet blanket...
        WELL_HAVE_I_GOT_JUST_THE_RIGHT_THING                                      = 8073,  -- Well, have I got just the right thing for you! A brand new make of Cardian, I call...
        TA_DA_THE_ALL_NEW_C_2000                                                  = 8074,  -- Ta`da`!!! The All-New C-2000!
        SO_HOW_ABOUT_IT_THEN_DO_YOU_HAVE                                          = 8075,  -- So how about it, then!? Do you have the inclination to go down in the history of our nation by helping in the creation of this amazing new innovation in automatons?
        WANT_TO_GO_DOWN_IN_HISTORY_YES_SIGN                                       = 8076,  -- Want to go down in history? Yes. Sign me up now! No, I'm turning you down.
        GEE_WHAT_DO_YOU_HAVE_TO_BE_SUCH                                           = 8077,  -- Gee... What do you have to be such a wet blanket for...?
        OH_GOOD_STICK_WITH_ME_KID_WITH_MY                                         = 8078,  -- Oh, good! Stick with me, kid--with my brains and your brawn, we're bound to go places together!
        YOU_SEE_I_JUST_HAPPENED_TO_BE_IN                                          = 8079,  -- You see...I just happened to be in the process of teaching The All-New C-2000 the scents of different enemies. The All-New C-2000 has a better nose than us people do, you knows?
        FOR_STARTERS_I_WAS_HOPING_YOU_COULD_BRING                                 = 8080,  -- For starters, I was hoping you could bring me some of the items that the monsters in Sarutabaruta drop.
        LET_ME_SEE_AND                                                            = 8081,  -- Let me see... % and %...
        OH_AND_WOULD_BE_NICE_TO_BEGIN_WITH                                        = 8082,  -- Oh, and % would be nice to begin with. So good luck and goodbye! See you when you've obtained one of each of those items...
        HAVE_YOU_OBTAINED_THE_ITEMS_I_NEED_TO                                     = 8083,  -- Have you obtained the items I need to educate the All-New C-2000 yet?
        DON_T_FORGET_NOW_I_NEED_AND                                               = 8084,  -- Don't forget, now... I need %, %, and %.
        SO_HURRY_HUR_RY_YOU_DON_T_WANT                                            = 8085,  -- So hurry, hur`ry! You don't want someone else to beat you to it, and have their name go down in history instead of yours, do you?
        CARDIANS_AREN_T_PEOPLE_YOU_KNOW_WHOW_THEY                                 = 8086,  -- Cardians aren't people, you know-whow? They are like dolls made out of all sorts of materials. We place the magic on those dolls that breathes life into them.
        BUT_EACH_AND_EVERY_CARDIAN_IS_AN_INDIVIDUAL                               = 8087,  -- But each and every Cardian is an individual. The character of the person who casts the life-giving magic on them is reflected in their personalities, too!
        THE_CARDIANS_THAT_KOPURO_POPURO_MAKES_CAUSE_ALL                           = 8088,  -- The Cardians that Kopuro-Popuro makes cause all sorts of trouble. We can't take our eyes off of them for too long...
        MINISTER_APURURU_IS_TOO_SOFT_ON_HIM_THE                                   = 8089,  -- Minister Apururu is too soft on him. The future of our Manustery is bleak indeed!
        MISTER_KOPURO_POPURO_MIXES_AND_MATCHES_THE_MAGICKY                        = 8090,  -- Mister Kopuro-Popuro mixes and matches the magicky he casts on Cardians in order to animatey them.
        THE_LIFE_BRINGING_MAGICKY_USED_ON_CARDIANS_IS                             = 8091,  -- The life-bringing magicky used on Cardians is extremely difficult to do. Wow, I hope if I keep practicing hard enoughy, I'll also be able to performy all sorts of variations of that magicky just like he does.
        MIGHTY_OBLIGED_TO_YOU_THERE_FRIEND_YOUR_NAME                              = 8092,  -- Mighty obliged to you there, friend. Your name will go down in Windurstian history for sure now!
        SO_DON_T_COMPLAIN_IF_YOUR_REWARD_ISN                                      = 8093,  -- So don't complain if your reward isn't as good as expected, kid.
        THIS_IS_HOW_WE_TEACH_THE_CARDIANS_WE                                      = 8094,  -- This is how we teach the Cardians we create to remember all kinds of things.
        I_GUESS_IT_S_KIND_OF_LIKE_BEING                                           = 8095,  -- I guess it's kind of like being their mother or father.
        HEY_YOU_VE_COME_BACK_HERE_AGAIN                                           = 8096,  -- Hey, you've come back here again?
        OH_WELL_SEEING_AS_YOU_RE_HERE_YOU                                         = 8097,  -- Oh well, seeing as you're here, you might as well make yourself useful. You see, I've just made another new type of Cardian. This time, I'm calling it...
        TA_DA_THE_ALL_NEW_C_2000_2                                                = 8098,  -- Ta`da`!!! The All-New C-2000!
        HUH_WHADDAYAMEAN_YEAH_YEAH_I_VE_HEARD_IT                                  = 8099,  -- Huh...? Whaddayamean, Yeah, yeah, I've heard it before?
        NEXT_YOU_LL_BE_TELLING_ME_YOU_KNOW                                        = 8100,  -- Next you'll be telling me you know what items I want you to bring, rightaru? Anyway, I guess that means you'll be helping me out, then?
        AGREE_TO_HELP_HIM_OUT_YEAH_NAW                                            = 8101,  -- Agree to help him out? Yeah. Naw.
        GEE_YOU_DON_T_HAVE_TO_BE_SUCH_2                                           = 8102,  -- Gee...you don't have to be such a tease!
        GREAT_HEAD_ON_OUT_TO_SARUTABARUTA_AND_PROCURE                             = 8103,  -- Great! Head on out to Sarutabaruta and procure me those items, then!
        ONE_SREE_TINGS_ONE_SREE_TINGS                                             = 8104,  -- ONE'SREE-TINGS... ONE'SREE-TINGS...?
        WHAT_IS_SPARE_ONE_S_GREETING_GIMME_FIVE                                   = 8105,  -- What is Spare One's greeting? Gimme five! Hang ten, dood! Wassuuuuuup?
        ONE_SREE_TINGS_GIMMEIVE                                                   = 8106,  -- ONE'SREE-TINGS... GIMMEIVE!
        ONE_SREE_TINGS_HANGENOOD                                                  = 8107,  -- ONE'SREE-TINGS... HANGENOOD!
        ONE_SREE_TINGS_WASSUUUUUUUP                                               = 8108,  -- ONE'SREE-TINGS... WASSUUUUUUUP?
        DON_T_GO_TEACHYING_THAT_KIDDY_STRANGE_WORDIES                             = 8109,  -- Don't go teachying that kiddy strange wordies! It's practically impossible to make Cardians forgety something once they memorizey it!
        THAT_SPARE_ONEY_THERE_IS_BUT_A_NEWBORNY                                   = 8110,  -- That Spare Oney there is but a newborny Cardian! So he memorizes anythingy and everythingy without reservation.
        THE_OTHER_DAY_KOPURO_POPURO_WENT_AND_TAUGHT                               = 8111,  -- The other day Kopuro-Popuro went and taught one of our Kindercardianers the words hats suck and upset old Boizo-Naizo to no end.
        NEWBORN_CARDIANS_ARE_JUST_LIKE_ORDINARY_PEOPLE_S                          = 8112,  -- Newborn Cardians are just like ordinary people's children, so you have to teach them to use words properly-woperly!
        HEY_YOU_THEREY_REMEMBER_THAT_CARDIANY_YOU_TAUGHT                          = 8113,  -- Hey, you therey! Remember that Cardiany you taught a silly greeting to the other day?
        THAT_POOR_CARDIANY_JUST_WOULDN_T_FORGETY_THE                              = 8114,  -- That poor Cardiany just wouldn't forgety the words you taughty it.
        SEEING_AS_IT_WAS_YOU_WHO_TAUGHTY_THE                                      = 8115,  -- Seeing as it was you who taughty the poor thingy an inappropriate greeting, you should take responsibility for your actions and teachy him a correct way of greeting otheries!
        IF_SOMETHINGY_S_NOT_DONE_HE_LL_HAVE                                       = 8116,  -- If somethingy's not done, he'll have to livey in embarrassment as a poorly-trained Cardian for the resty of his days. Wouldn't that be a pity-wity?
        THINK_IT_S_PITIABLE_YES_THAT_S_SAD                                        = 8117,  -- Think it's pitiable? Yes, that's sad. Not really...
        YOU_INHUMANE_BRUTEY_HAVE_YOU_NO_FEELINGIES                                = 8118,  -- You inhumane brutey! Have you no feelingies?
        AS_CARDIANS_GROW_UP_AND_RISE_IN_RANKY                                     = 8119,  -- As Cardians grow up and rise in ranky, their names changey. So, that Spare Cardian you spoke to backy then has a different namey that goes with the position he filledy.
        I_THINK_HIS_NAMEY_IS_NOW_FIVE_OF                                          = 8120,  -- I think his namey is now Five of something-or-othery...?
        WELL_I_DON_T_KNOWY_THEIR_NAMES_CHANGEY                                    = 8121,  -- Well, I don't knowy...!? Their names changey so much, it's practically impossible to keep tracky of who's who!
        ANYWAY_TRY_GOING_AROUNDY_AND_TALKING_TO_THE                               = 8122,  -- Anyway, try going aroundy and talking to the Cardians of each suit with the namey Five, and use the greeting you taught him as a signy to tell him apart from the otheries.
        THE_CARDIAN_WHOSE_LIFEY_YOU_RUINED_BY_TEACHING                            = 8123,  -- The Cardian whose lifey you ruined by teaching him a silly greeting should now be named Five of something-or-othery...?
        ANYWAY_TRY_GOING_AROUNDY_AND_TALKING_TO_THE_2                             = 8124,  -- Anyway, try going aroundy and talking to the Cardians of each suit with the namey Five, and use the greeting you taught him as a signy to tell him apart from the otheries.
        THE_CARDIANS_OF_WINDURST_ARE_DEALT_OUT_NUMBERS                            = 8125,  -- The Cardians of Windurst are dealt out numbers in the order that they are born. When their numerical predecessor breaks down, all the Cardians below him rise in rank to fill out the numbers of a full deck.
        SO_THE_MORE_CARDIANS_THAT_BECOME_RUN_DOWN                                 = 8126,  -- So the more Cardians that become run-down or destroyed, the faster the numbers in the names of their successors change.
        OH_YOU_MEAN_THAT_CARDIAN_SO_HE_S                                          = 8127,  -- Oh, you mean that Cardian...? So he's grown up to become number five already, huh?
        SIGH_WHEN_I_HEAR_THAT_IT_BRINGS_HOME                                      = 8128,  -- <Sigh>... When I hear that, it brings home to me just how short the lifespans of our Cardians are becoming...
        I_BELIEVE_THAT_PARTICULAR_CARDIAN_YOU_SPEAK_OF                            = 8129,  -- I believe that particular Cardian you speak of was made by Kopuro-Popuro.
        KOPURO_POPURO_HAS_A_HABIT_OF_FORGETTING_IMPORTANT                         = 8130,  -- Kopuro-Popuro has a habit of forgetting important things while always remembering the most useless of information. Like father, like son, eh?
        SO_DID_YOU_FINDY_HIM_WHAT_DO_YOU                                          = 8131,  -- So, did you findy him...? What do you meany, he's outsidey of town? Eh? He's that far away from towny?
        WHAT_S_HE_DOING_IN_SUCH_A_DANGEROUS                                       = 8132,  -- What's he doing in such a dangerous placey? We'd better hurry and send someone out to bring him backy! Here...takey this as a little thank-you for finding himy!
        IF_HE_STAYS_OUTSIDE_OF_TOWNY_TOO_LONG                                     = 8133,  -- If he stays outside of towny too long, there's a chance people might mistakey him for one of those feral Cardians and killy him!
        WHAT_S_HE_DOING_IN_SUCH_A_DANGEROUS_2                                     = 8134,  -- What's he doing in such a dangerous placey? We'd better hurry and send someone out to bring him backy!
        IF_HE_STAYS_OUTSIDE_OF_TOWNY_TOO_LONG_2                                   = 8135,  -- If he stays outside of towny too long, there's a chance people might mistakey him for one of those feral Cardians and killy him!
        WHAT_S_HE_DOING_IN_SUCH_A_DANGEROUS_3                                     = 8136,  -- What's he doing in such a dangerous placey? We'd better hurry and send someone out to bring him backy!
        IT_IS_TRUE_THAT_THE_NUMBERS_THE_CARDIANS                                  = 8137,  -- It is true that the numbers the Cardians are called by change a lot lately, but we should not forget the individual students behind those names.
        THIS_FACILITY_IS_DIFFERENT_FROM_SCHOOLS_WHERE_THEY                        = 8138,  -- This facility is different from schools where they teach people how to study-wudy. This is more like a home where we raise children in a loving way.
        SAY_I_WONDER_WHETHER_THAT_CARDIAN_PROPERLY_FORGOT                         = 8139,  -- Say...I wonder whether that Cardian properly forgot the hats suck line I taught him?
        I_DON_T_THINK_WE_SHOULD_FORCE_CARDIANS                                    = 8140,  -- I don't think we should force Cardians to forget things they don't want to forget.
        IT_WOULDN_T_HURT_FOR_OUR_CARDIANS_TO                                      = 8141,  -- It wouldn't hurt for our Cardians to have a little more individuality now, would it?
        WE_RE_IN_DEEP_WATER_EVERYONE                                              = 8142,  -- We're in deep water, everyone!
        WE_RE_IN_THE_RED_AGAIN_THIS_WEEK                                          = 8143,  -- We're in the red again this week.
        AND_AFTER_ALL_OF_THOSE_CUTBACKS_WE_VE                                     = 8144,  -- And after all of those cutbacks we've been implementing lately, too...
        I_D_LIKE_TO_ASK_YOU_ALL_FOR                                               = 8145,  -- I'd like to ask you all for ideas... How can we get some gil back into the Manustery's coffers?
        I_KNOW_MINISTER_APURURU_IT_LOOKS_LIKE_IT                                  = 8146,  -- I know, Minister Apururu! It looks like it's time to implement Legendary Plan B!
        LEGENDARY_WARY                                                            = 8147,  -- Legendary-wary?
        PLAN_B                                                                    = 8148,  -- Plan B?
        LONG_LONG_AGO_OUR_OLD_MANUSTERY_WAS_FACING                                = 8149,  -- Long, long ago, our old Manustery was facing a financial crisis much like we are today...
        THIS_WAS_IN_AN_AGE_LONG_BEFORE_AIRSHIPS                                   = 8150,  -- This was in an age long before airships connected the cities of Vana'diel with the convenient network we have now.
        BACK_THEN_TRAVELERS_ON_THEIR_WAY_TO_JEUNO                                 = 8151,  -- Back then, travelers on their way to Jeuno were menaced by fearsome nocturnal-wurnal monsters.
        TO_BRIGHTEN_UP_THE_FUTURE_FOR_THOSE_TRAVELERS                             = 8152,  -- To brighten up the future for those travelers, our predecessors, in their great wisdom, devised a charm for trekkers they called the Gadabout's Gris-gris!
        THE_EFFECT_OF_THESE_CHARMS_WAS_ASTOUNDING_AND                             = 8153,  -- The effect of these charms was astounding, and the reduction in the number of dangerous incidents that befell Jeuno-bound travelers was significant.
        HMM_OH_REALLY_WELL_I_DON_T_KNOW                                           = 8154,  -- Hmm... Oh, really? Well, I don't know whether it's true or just an old wives' tale, but we could make a load of gil by selling such charms to the local goods stores, couldn'taru we?
        THAT_WAS_MIGHTY_USEFUL_INFORMATION_ESPECIALLY_COMING_FROM                 = 8155,  -- That was mighty useful information, especially coming from the likes of Kopuro-Popuro. So, how does one go about making these Gadabout's Gris-gris thingamabobs?
        WELL_YOU_NEED_ALL_KINDS_OF_ITEMS_THAT                                     = 8156,  -- Well, you need all kinds of items that nocturnal monsters drop when defeated.
        IN_ORDER_TO_MAKE_A_CHARM_I_THINK                                          = 8157,  -- In order to make a charm, I think we just need: %, %, and %.
        I_SEE_GREAT_THEN_WE_LL_JUST_MAKE                                          = 8158,  -- I see... Great! Then we'll just make a heap of them to sell. We'll have money back in the Manustery's coffers in no time!
        YOU_LL_HELP_US_OUT_AS_WELL_WON                                            = 8159,  -- You'll help us out as well, won'taru you? Please collect one of each of the items that the nocturnal monsters drop.
