        I_SEE_SUCH_A_MISFORTUNATE_EPISODE_HAS_CAUSED                              = 8452,  -- I see... Such a misfortunate episode has caused the poor thing to cease functioning.
        THE_MANA_ORB_THE_HEART_OF_THIS_CARDIAN                                    = 8453,  -- The Mana Orb--the heart of this Cardian--is still glowing. This is not a mere case of magic energy depletion. This child's heart has been broken-woken.
