        THIS_CARDIAN_YOU_BROUGHT_ME_WAS_MADE_DURING                               = 8456,  -- This Cardian you brought me was made during the war years, so it has probably felt its fair share of sorrow over its lifetime.
        SIGH_I_WONDER_IF_I_CAN_HEAL_THE                                           = 8457,  -- <Sigh>... I wonder if I can heal the poor thingy-wingy?
