        BUT_I_LL_NEED_HELP_TO_CARRY_IT                                            = 8460,  -- But I'll need help to carry it out. Would you be so good as to assist me?
        HELP_FIX_THE_CARDIAN_YES_ANYTHING_TO_HELP                                 = 8461,  -- Help fix the Cardian? Yes. Anything to help! Sorry, I can't.
