        IN_ORDER_TO_DO_THAT_I_LL_NEED                                             = 8463,  -- In order to do that, I'll need to pair it off with its opposing Cardian Card--the ten of cups. I only need a single ten of cups card, so could you be so good as to obtain one for me?
        SOME_OF_THE_OLD_TYPE_OF_CARDIANS_WHO                                      = 8464,  -- Some of the old type of Cardians--who are now malfunctioning and breaking down--run wild in the southwestern parts of the Horutoto Ruins. That would be the best place to search. But please be very careful-wareful!
        THAT_S_TOO_BADY_WADY_SNIFF                                                = 8465,  -- That's too bady-wady...<sniff>
        THE_TEN_OF_CUPS_IS_THE_OPPOSING_CARD                                      = 8466,  -- The Ten of Cups is the opposing card to our poor little Cardian friendy-wiendy. If you bring me %, I can remove the old magic from him and commence my repairs.
        SOME_OF_THE_OLD_STYLE_CARDIANS_THAT_HAVE                                  = 8467,  -- Some of the old-style Cardians that have long malfunctioned run wild in the southwestern parts of the Horutoto Ruins of West Sarutabaruta. Try searching there. But please be very careful-wareful!
