        THERE_ARE_MANY_TABOOS_WHEN_ONE_BREATHES_LIFE                              = 8472,  -- There are many taboos when one breathes life into these automaton dolls, you know, kid?
        ONE_VERY_IMPORTANT_RULE_IS_TO_NEVER_CAST                                  = 8473,  -- One very important rule is to never cast a second batch of magic on a doll that already has magic placed on it. If you're not careful, either you or the doll could die! Shivers!
