        BUT_I_NEED_TO_WIPE_HIS_MANA_ORB                                           = 8476,  -- But... I need to wipe his Mana Orb clean in order to begin... I must clean away the memories that broke his heart...
        TELL_THIS_CHILD_S_FRIENDS_BACK_IN_JEUNO                                   = 8477,  -- Tell this child's friends back in Jeuno that it won't be much longer before he's as good as new.
        I_I_NEED_TO_WIPE_HIS_MANA_ORB                                             = 8478,  -- I... I need to wipe his Mana Orb clean in order to begin. I must clean away the memories that broke his heart...
        OOH_SCARY_WAREY_DON_TY_YOU_GO_DISTURBINGY                                 = 8479,  -- Ooh, scary-warey! Don'ty you go disturbingy Minister Apururu now!
        THE_MAGIC_NEEDED_TO_BREATHE_LIFEY_INTO_A                                  = 8480,  -- The magic needed to breathe lifey into a Cardian are all very delicate operationies. She has to keepy her concentration, she does!
        THE_MINISTER_IS_SO_DETERMINED_WERMINED_I_DON                              = 8481,  -- The minister is so determined-wermined. I don'taru want her to go through with this, but it looks like nothing would stop her now.
        SHE_TENDS_TO_GET_CARRIED_AWAY_WHEN_IT                                     = 8482,  -- She tends to get carried away when it comes to matters about her father. We have to look out for her as much as we can!
        THERE_ARE_MANY_TABOOS_WHEN_ONE_BREATHES_LIFE_2                            = 8483,  -- There are many taboos when one breathes life into these automaton dolls, you know, kid?
        ONE_VERY_IMPORTANT_RULE_IS_TO_NEVER_CAST_2                                = 8484,  -- One very important rule is to never cast a second batch of magic on a doll that already has magic placed on it. If you're not careful, either you or the doll could die! Shivers!
