        BUT_ANYWAYS_I_M_GLAD_THAT_LITTLE_MATTA                                    = 8494,  -- But, anyways, I'm glad that little matta is overrr! Quite relieved!
        SO_IT_WAS_JUST_ANOTHERRR_MITHRA_WHO_HAS                                   = 8495,  -- So it was just anotherrr Mithra who has a similarrr name to our boss, Hae Jakkya, who borrowed the saucy romance novel... Well, that was a letdown!
