        RANK_3_LMV_UCK003_A_V_V_LEFT                                              = 8651,  -- RANK 3... %lmv uck003:A;V`%[v LEFT ZONE ONCE. RESET ALL QUEST FLAGS.
        RANK_5_V_LEFT_ZONE_ONCE_RESET_ALL                                         = 8652,  -- RANK 5... %v LEFT ZONE ONCE. RESET ALL QUEST FLAGS.
        OTHER_RANKS_V_UJNE003_JEUNOLJJV_R_A_L                                     = 8653,  -- OTHER RANKS: %=#{%*v ujne003:JeunoLJJV@r%=A_l%%%$L$=%v usf001:V[tA[eBt@Ngv ukjb001:klA[eBt@Ngv
        SET_WHICH_FLAGS_TE001OK_FLAG_TE001START_FLAG_GAVE                         = 8654,  -- SET WHICH FLAGS? @te001OK FLAG. te001START FLAG. GAVE ITEM FLAG. JUST AFTER te001END FLAG. RESET ALL QUEST FLAGS.
        SET_WHICH_FLAGS_DB001OK_FLAG_DID_GREETING_MOTION                          = 8655,  -- SET WHICH FLAGS? @db001OK FLAG. DID GREETING MOTION. db001START FLAG. GAVE YAGUDO ITEM. JUST AFTER db001END FLAG. RESET ALL QUEST FLAGS.
