        SET_WHICH_FLAGS_HA005OK_FLAG_RECEIVED_RIBBON_HA005END                     = 8658,  -- SET WHICH FLAGS? @ha005OK FLAG. RECEIVED RIBBON. ha005END< FLAG. RESET ALL QUEST FLAGS.
        SET_WHICH_FLAGS_HUNTER_JOB_OK_FLAG_HUNTER                                 = 8659,  -- SET WHICH FLAGS? @HUNTER JOB OK FLAG. HUNTER JOB START FLAG. GAVE FALSE FANG. GAVE REAL FANG. HUNTER JOB END< FLAG. RESET ALL QUEST FLAGS.
        SET_WHICH_FLAGS_START_FLAG_TOUCHED_DOOR_QUEST                             = 8660,  -- SET WHICH FLAGS? START FLAG. TOUCHED DOOR. QUEST FINISHED.
        SET_WHICH_FLAGS_KR001OK_FLAG_KR001START_FLAG_GAVE                         = 8661,  -- SET WHICH FLAGS? KR001ok FLAG. KR001start FLAG. GAVE AS. QUEST FINISHED.
