        SET_WHICH_FLAGS_JNE003MI_FLAG_JNE003CARD_FLAG                             = 8665,  -- SET WHICH FLAGS? JNE003mi FLAG. JNE003card FLAG.
        SET_WHICH_FLAGS_TE005OK_FLAG_TE005START_FLAG_HEARD                        = 8666,  -- SET WHICH FLAGS? TE005OK FLAG. TE005start FLAG. HEARD IT FROM Boizo-Naizo. GOT ITEM (in front of Apururu). QUEST FINISHED.
        SET_WHICH_FLAGS_ZS002MI_FLAG_ZS002END_FLAG                                = 8667,  -- SET WHICH FLAGS? ZS002mi FLAG. ZS002end FLAG.
        SET_WHICH_FLAGS_ME003MI_FLAG_ME003END_FLAG                                = 8668,  -- SET WHICH FLAGS? ME003mi FLAG. ME003end FLAG.
        TO_DIEU_XH_SF001_SF002S_SF002_2QBG_SF002                                  = 8669,  -- tO'DiEU[}XH SF001 SF002s/=< SF002%^2Qbg SF002 SF003s/=< SF003%A=
        TO_DIEU_XH_KJB011_O_KJB011_KJB011OA                                       = 8670,  -- tO'DiEU[}XH KJB011%O KJB011 KJB011oA=
        HOW_ABOUT_THIS_FOR_A_MISSION_THE_SCHOOL                                   = 8671,  -- How about this for a mission? The School of Magic, conducted by the Aurastery, is seeking an able adventurer to help them out.
        HOWEVER_IT_SEEMS_THAT_THIS_MISSION_WILL_RRREQUIRE                         = 8672,  -- However, it seems that this mission will rrrequire several days of hard effort. What do you think? Will you give it a try?
        ACCEPT_THE_MISSION_ACCEPT_DECLINE                                         = 8673,  -- Accept the mission? Accept. Decline.
        THE_AURASTERY_S_SCHOOL_OF_MAGIC_IS_ON                                     = 8674,  -- The Aurastery's School of Magic is on the eastern side of Windurst Waters. Just head north from Windurst Waters's rrresidential area entrance.
        THE_SCHOOL_IS_FULL_OF_CHILDREN_STRIVING_TO                                = 8675,  -- The school is full of children striving to become tomorrow's politicians and scholars. Putting up with them is a greater test of endurance than any mission I can issue you!
        THE_AURASTERY_S_SCHOOL_OF_MAGIC_IS_ON_2                                   = 8676,  -- The Aurastery's School of Magic is on the eastern side of Windurst Waters. Just head north from Windurst Waters's rrresidential area entrance.
        THE_SCHOOL_IS_FULL_OF_CHILDREN_STRIVING_TO_2                              = 8677,  -- The school is full of children striving to become tomorrow's politicians and scholars. Putting up with them is a greater test of endurance than any mission I can issue you!
        THE_THE_KIDDY_WIDDIES_WHO_STUDY_AT_THE                                    = 8678,  -- The, the kiddy-widdies who study at the School of Magic are all super-smart. Once they gra-graduate, they can automatically enter one of the m-ministries.
        IN_IN_FACT_M_MOST_GO_ON_TO                                                = 8679,  -- In, in fact, m-most go on to become the m-ministers of the m-ministries! S-saying they have great potential is an understatement-batement!
        WHY_WOULD_TARUTARU_CHILDREN_EVERRR_WANT_TO_STUDY                          = 8680,  -- Why would Tarutaru children everrr want to study at a School of Magic?
        GRRR_I_D_HATE_TO_BE_FORRRCED_TO                                           = 8681,  -- Grrr... I'd hate to be forrrced to sit in front of a desk all day. It sounds like a punishment to me.
