        ARE_YOU_SURE_YOU_WANT_TO_PURCHASE_THE                                     = 9034,  -- Are you sure you want to purchase the %?
        PROCEED_YES_PURCHASE_ITEM_CANCEL_PURCHASE                                 = 9035,  -- Proceed? Yes, purchase item. Cancel purchase.
        PROCEED_YES_EVEN_THOUGH_I_CAN_T_EQUIP                                     = 9036,  -- Proceed? Yes, even though I can't equip it. Cancel purchase.
