        ARE_YOU_READY_FOR_A_SPINE_CHILLING_STOMACH                                = 9843,  -- Are you ready for a spine-chilling, stomach-churning test of your mettle, kupo!?
        WE_VE_SET_UP_A_SECRET_MARKER_SOMEWHERE                                    = 9844,  -- We've set up a secret marker somewhere in the bowels of a dreadful dungeon. Your goal is to reach that marker alive, kupo!
        OH_A_NEW_ADVENTURER_BEST_OF_LUCK_KUPO                                     = 9845,  -- Oh, a new adventurer! Best of luck, kupo!
        ARE_YOU_HELPING_OUT_THE_NEW_ADVENTURERS_BEST                              = 9846,  -- Are you helping out the new adventurers? Best of luck in your endeavors, kupo!
