        HERE_S_YOUR_REWARD_FOR_REACHING_THE_GOAL                                  = 9848,  -- Here's your reward for reaching the goal, kupo!
        WEAR_THE_YUKATA_THE_NEXT_TIME_YOU_COME                                    = 9849,  -- Wear the yukata the next time you come to see me! I can't wait to see how you look, kupo!
        PARTNER_UP_WITH_LOTS_OF_DIFFERENT_ADVENTURERS_AND                         = 9850,  -- Partner up with lots of different adventurers and bring back all kinds of trophies to prove your courage! When you've brought enough, I'll give you something really special, kupo!
        THE_FACE_IN_THE_PORTRAIT_YOU_BROUGHT_ME                                   = 9851,  -- The face in the portrait you brought me is just... Kupupupu!
        INCREDIBLE_KUPO_YOU_MUST_HAVE_NERVES_OF_DARKSTEEL                         = 9852,  -- Incredible, kupo! You must have nerves of darksteel! Here, you've earned this, kupo!
        YOU_TOOK_ANOTHER_DIVE_INTO_THE_DREADED_DUNGEON                            = 9853,  -- You took another dive into the dreaded dungeon, kupo? Well, you deserve a little something for your preternatural perseverance, kupo.
        YOU_HAVEN_T_EARNED_MY_REALLY_SPECIAL_PRESENT                              = 9854,  -- You haven't earned my really special present yet! Only truly dauntless dungeon-delvers get that, kupo!
        THIS_ISN_T_ENOUGH_TO_PROVE_YOU_REACHED                                    = 9855,  -- This isn't enough to prove you reached the goal as a dungeon-delving duo. You have to bring me the item your partner received to show that you were both successful, kupo!
        TO_GO_ON_THIS_FRIGHT_FILLED_FACE_OFF                                      = 9856,  -- To go on this fright-filled face-off with fear, you need a partner who can prove you reached the goal. Come back when you have a buddy in bravery, kupo!
        THIS_ADVENTURE_INTO_ADVERSITY_IS_ONLY_AVAILABLE_TO                        = 9857,  -- This adventure into adversity is only available to two-person parties. Split up into pairs and talk to me again, kupo!
        PLEASE_COME_BACK_WITH_A_DIFFERENT_PARTNER_IT                              = 9858,  -- Please come back with a different partner. It'll be no fun to scare you if your reactions are too similar, kupo!
        YOUR_PARTNER_ISN_T_READY_TO_GO_PLEASE                                     = 9859,  -- Your partner isn't ready to go. Please wait a little longer, kupo.
        YOUR_PARTNER_MUST_TALK_TO_ME_AS_WELL                                      = 9860,  -- Your partner must talk to me as well. I'll be waiting for you whenever you're ready, kupo.
        YOU_CAN_ONLY_CHOOSE_ONE_PARTNER_A_DAY                                     = 9861,  -- You can only choose one partner a day. Come back again tomorrow, kupo!
        HOLD_UP_THERE_IT_LOOKS_LIKE_YOUR_CANDIDATE                                = 9862,  -- Hold up there! It looks like your candidate for courageous companionship has already got a partner! You can't choose that person at the moment, kupo!
        PLEASE_WAIT_A_LITTLE_LONGER_OR_FIND_A                                     = 9863,  -- Please wait a little longer or find a new partner before coming back, kupo.
        ARE_YOU_READY_TO_TEST_YOUR_COURAGE_KUPO                                   = 9864,  -- Are you ready to test your courage, kupo?
        ARE_YOU_READY_TO_GO_READY_KUPO_I                                          = 9865,  -- Are you ready to go? Ready, kupo! I'm too terrified, kupo!
        I_LL_BE_CHECKING_TO_SEE_IF_YOU                                            = 9866,  -- I'll be checking to see if you reached the goal. You can use this magical scroll to make a speedy return to town, kupo.
        IF_YOU_BOTH_SUCCEED_I_LL_HAVE_A                                           = 9867,  -- If you both succeed, I'll have a prize waiting for you! Now, off you go, kupo!
        YOU_CAN_ONLY_CARRY_ONE                                                    = 9868,  -- You can only carry one %.
        ARE_YOU_PARTICIPATING_IN_THIS_PETRIFYING_PILGRIMAGE_WITH                  = 9869,  -- Are you participating in this petrifying pilgrimage with the person in your present party?
        HEY_YOU_CHANGED_PARTNERS_YOU_CAN_T_SWITCH                                 = 9870,  -- Hey, you changed partners! You can't switch halfway through, kupo!
        WAIT_THE_NUMBER_OF_PEOPLE_IN_YOUR_PARTY                                   = 9871,  -- Wait, the number of people in your party has changed! You have to be in a two-person party, kupo!
        CHOOSE_YOUR_PARTNER_WISELY_COME_BACK_WHEN_YOU                             = 9872,  -- Choose your partner wisely. Come back when you think you have a winning combo, kupo!
        BOO_HAH_HAH_KUPO                                                          = 9873,  -- Boo-hah-hah`...kupo!
        HUH_WHY_AREN_T_YOU_JUMPING_OUT_OF                                         = 9874,  -- Huh? Why aren't you jumping out of your skin in absolute terror? I would've died of fright, kupo!
        HERE_TAKE_THIS_AS_A_TESTAMENT_TO_YOUR                                     = 9875,  -- Here, take this as a testament to your courage. Exchange it for the item your partner received so you can prove that you both reached the goal safely, kupo!
        RETURN_WITH_THE_EVIDENCE_OF_YOUR_SUCCESS_TO                               = 9876,  -- Return with the evidence of your success to the moogle in town. Handing over your partner's item will prove that you were both able to reach me, kupo!
        OH_AND_HERE_S_A_PICTURE_OF_HOW                                            = 9877,  -- Oh, and here's a picture of how your partner's face looked when I popped out of nowhere to scare you. You should hand this in at the same time, kupo! Kupupupu...
        THIS_PLACE_IS_CRAWLING_WITH_NASTIES_YOU_SHOULD                            = 9878,  -- This place is crawling with nasties. You should probably head back to town so you can testify to your partner's bravery.
        WHY_DO_GHOSTS_SAY_BOO_ANYWAY                                              = 9879,  -- Why do ghosts say boo, anyway?
        I_HEARD_THAT_GOING_TO_A_DARK_SCARY                                        = 9880,  -- I heard that going to a dark, scary dungeon is the best way to test your courage. This place definitely qualifies, kupo!
        MAYBE_I_M_DOING_SOMETHING_WRONG_KUPO                                      = 9881,  -- Maybe I'm doing something wrong, kupo?
        IF_IT_GETS_OUT_THAT_I_HAVEN_T                                             = 9882,  -- If it gets out that I haven't scared the wits out of a single person yet, I'm going to get into trouble, kupo...
        UNABLE_TO_ENTER_NEXT_AREA_EXPANSION_PACK_NOT                              = 9883,  -- Unable to enter next area. Expansion pack not installed.
