        BEFORE_YOU_CAN_TAKE_PART_IN_THIS_CONFLICT                                 = 9885,  -- Before you can take part in this Conflict event, you must first possess %. You can obtain one from your nation's Conflict Commander, [Excenmille, stationed in Northern San d'Oria./Invincible Shield, stationed in the Metalworks in Bastok./Mhabi Molkot, stationed in Heavens Tower in Windurst.]
        ONLY_ADVENTURERS_WHO_HAVE_ACHIEVED_RANK_3_OR                              = 9886,  -- Only adventurers who have achieved rank 3 or higher may take part in official Ballista matches. Please return when you have proven your loyalty to your home nation.
        HOWEVER_IF_YOU_STILL_WISH_TO_TAKE_PART                                    = 9887,  -- However, if you still wish to take part in Ballista, participation in matches held within Diorama Abdhaljs-Ghelsba is open to all citizens of Vana'diel.
        WHAT_SERVICES_DO_YOU_REQUIRE                                              = 9888,  -- What services do you require?
        WHAT_CAN_I_HELP_YOU_WITH_NOTHING_THE                                      = 9889,  -- What can I help you with? Nothing. The upcoming Ballista matches. The Ballista schedule. A teleport to the Ballista match. The rules of Ballista. Borrow/Return %. Borrow/Return %. Borrow/Return %. The upcoming Brenner matches. A teleport to the Brenner match (Lv #). The rules of Brenner. Borrow/Return %. Borrow/Return %.
        I_AM_ALLOWED_TO_TELEPORT_BALLISTA_PARTICIPANTS_TO                         = 9890,  -- I am allowed to teleport Ballista participants to the site of the next match in exchange for % or # Ballista [Point/Points]. This service is available from twenty-four hours before the start of the match, up until the end of the match.
        CAN_BE_RECEIVED_AFTER_PARTICIPATING_IN_BALLISTA_OR                        = 9891,  -- % can be received after participating in Ballista, or in the event one is not able to participate due to an influx (or lack) of entries.
        I_M_SORRY_BUT_I_AM_NOT_AUTHORIZED                                         = 9892,  -- I'm sorry, but I am not authorized to teleport persons who do not meet the level requirement for the match.
