        WHILE_WEARING_DURING_A_MATCH_YOU_WILL_BE                                  = 9903,  -- While wearing % during a match, you will be able to hear the orders of your nation's Pursuivant. His advice will aid you in battle.
        ALSO_YOU_WILL_BE_INFORMED_OF_ALL_THE                                      = 9904,  -- Also, you will be informed of all the latest match information when entering select cities.
        WOULD_YOU_LIKE_YES_NO                                                     = 9905,  -- Would you like %? Yes. No.
        RETURN_YOUR_YES_NO                                                        = 9906,  -- Return your %? Yes. No.
