        BY_CARRYING_WITH_YOU_DURING_A_BALLISTA_MATCH                              = 9908,  -- By carrying % with you during a Ballista match, any temporary item you quarry will be automatically placed in your bag without you having to select whether you wish to keep it, use it, or throw it away.
        WHEN_YOUR_INVENTORY_IS_FULL_OR_YOU_CANNOT                                 = 9909,  -- When your inventory is full, or you cannot carry any more of a certain item, the newly quarried item will be automatically discarded. If you wish, I can lend you one of these shovels, free of charge.
        BORROW_YES_NO                                                             = 9910,  -- Borrow %? Yes. No.
