        RETURN_THE_YES_NO                                                         = 9912,  -- Return the %? Yes. No.
        YOU_RETURN_THE                                                            = 9913,  -- You return the %!
        WHEN_CARRYING_WITH_YOU_WHILE_PARTICIPATING_IN_A                           = 9914,  -- When carrying % with you while participating in a Ballista match, you will have the option to keep or throw away the first Petra you find. This is useful when you want to continue /sprinting.
        IF_YOU_WISH_I_CAN_LOAN_YOU_ONE                                            = 9915,  -- If you wish, I can loan you one, free of charge.
