        HELPING_YOUR_TEAM_INTO_FIRST_WILL_GIVE_YOU                                = 12504,  -- Helping your team into first will give you certain advantages over your rivals! That should give you something to strive for!
        WHAT_WOULD_YOU_LIKE_TO_KNOW_ABOUT_THE                                     = 12505,  -- What would you like to know about? The promenade. Chocobet centers. The grandstand. Portals. Guides. Nothing for now.
        SHOPS_AS_WELL_AS_ATTENDANTS_TO_ASSIST_YOU                                 = 12506,  -- Shops, as well as attendants to assist you in siging up your chocobo for a race, are located on the promenade.
        IT_CAN_BE_FOUND_JUST_SOUTH_OF_HERE                                        = 12507,  -- It can be found just south of here.
        THE_PROMENADE_ITSELF_IS_SPLIT_INTO_EASTERN_AND                            = 12508,  -- The promenade itself is split into eastern and western halves, both of which house all of the same facilities. Be sure to stop by and have a look when you get a chance.
        ATTENDANTS_AT_THE_CHOCOBET_CENTERS_ARE_THERE_TO                           = 12509,  -- Attendants at the chocobet centers are there to assist you with acquiring %, as well as collecting your winnings.
        THERE_ARE_A_TOTAL_OF_FIVE_CENTERS_READILY                                 = 12510,  -- There are a total of five centers readily available for your convenience, each of which are located near the transportation portals. There are two to the east and west of here, and one just to the north.
        ALL_CHOCOBET_CENTERS_ARE_CAPABLE_OF_PROVIDING_THE                         = 12511,  -- All chocobet centers are capable of providing the same services.
        THE_GRANDSTAND_FACES_THE_RACETRACK_ITSELF_AND_ALLOWS                      = 12512,  -- The grandstand faces the racetrack itself, and allows spectators to sit and enjoy the races in comfort.
        TO_GET_THERE_JUST_FOLLOW_THE_RED_CARPET                                   = 12513,  -- To get there, just follow the red carpet all the way through the betting area. You can't miss it.
