        GOOD_DAY_TO_YOU_SIR_MA_AM_THIS                                            = 12618,  -- Good day to you, sir/ma'am]. This is the entrance to the Chocobo Circuit.
        THE_PORTALS_YOU_SEE_AROUND_YOU_CAN_BE                                     = 12619,  -- The portals you see around you can be used to grant passage to different racetracks.
