        I_AM_ZAHSA_SYALMHAIA_CAPTAIN_OF_THE_MERCENARIES                           = 13176,  -- I am Zahsa Syalmhaia, captain of the mercenaries in charge of defending East Sarutabaruta.
        AND_NOW_A_QUESTION_FOR_YOU_ADVENTURER_MIGHT                               = 13177,  -- And now, a question for you, adventurer--might you know the reason why Windurst's Mithran population is concentrated in the Woods district?
        HMPH_THEN_I_SHALL_ENLIGHTEN_YOU_THE_AREA                                  = 13178,  -- Hmph! Then I shall enlighten you. The area was given to us as a reward for our exceptional performance during the Great War!
        I_AM_ZAHSA_SYALMHAIA_CAPTAIN_OF_THE_MERCENARIES_2                         = 13179,  -- I am Zahsa Syalmhaia, captain of the mercenaries in charge of defending East Sarutabaruta.
        AND_NOW_A_QUESTION_FOR_YOU_ADVENTURER_DO                                  = 13180,  -- And now, a question for you, adventurer--do you know of the stone maws being found across the land? Some might describe them as cavernous.
        HMPH_THEN_I_SHALL_ENLIGHTEN_YOU_THEY_ARE                                  = 13181,  -- Hmph! Then I shall enlighten you. They are large statues of hideous visage, and have been around for some time. These maws are more than they appear, I guarantee you.
        OH_MY                                                                     = 13182,  -- Oh my!
