        I_LL_SEE_YOU_AGAIN                                                        = 13305,  -- I'll see you again.
        AHHH_A_PREMATURE_EXITARU                                                  = 13306,  -- Ahhh! A premature exitaru!
        YOU_RE_NOT_SUPPOSED_TO_CATCH_MANDRAGORAS                                  = 13307,  -- You're not supposed to catch mandragoras.
        PHEW_IS_IT_JUST_ME_OR_IS_IT                                               = 13308,  -- Phew...is it just me, or is it getting hot in here? Man, you look greataru in that bathing suit! You should try playing the game in hard mode!
        PHEW_IS_IT_JUST_ME_OR_IS_IT_2                                             = 13309,  -- Phew...is it just me, or is it getting hot in here? Man, you look greataru in that yukata! You should try playing the game in hard mode!
        PHEW_IS_IT_JUST_ME_OR_IS_IT_3                                             = 13310,  -- Phew...is it just me, or is it getting hot in here? Man, you look greataru in that happi! You should try playing the game in hard mode!
        PHEW_IS_IT_JUST_ME_OR_IS_IT_4                                             = 13311,  -- Phew...is it just me, or is it getting hot in here? Man, you look greataru in that outfit! You should try playing the game in hard mode!
        WHAT_WOULD_YOU_LIKE_TO_DO_LEARN_HOW_2                                     = 13312,  -- What would you like to do? Learn how to play. Check current high score. Play normal mode. Try hard mode. Nothing.
        IN_NORMAL_MODE_YOU_NEED_TO_CATCH_ONLY                                     = 13313,  -- In normal mode, you need to catch only 20 chicks in one minute to clear the game.
        BUT_IT_S_NO_CAKEWALK_IN_HARD_MODE                                         = 13314,  -- But it's no cakewalk in hard mode. You'll need at leastaru 35!
        CHECK_HIGH_SCORE_FOR_WHICH_MODE_NORMAL_MODE                               = 13315,  -- Check high score for which mode? Normal mode. Hard mode. Don't check.
        NORMAL_MODE_HIGH_SCORE_RECORD_HOLDER                                      = 13316,  -- Normal mode high score: # [chick/chicks]. Record holder: %.
        HARD_MODE_HIGH_SCORE_RECORD_HOLDER                                        = 13317,  -- Hard mode high score: # [chick/chicks]. Record holder: %.
        HERE_S_THE_REWARD_FOR_YOUR_EFFORTS_AND                                    = 13318,  -- Here's the reward for your efforts. And a bonus balloon, justaru for you!
        HUH_DID_THE_HEAT_JUST_EASE_OFF_A                                          = 13319,  -- Huh? Did the heat just ease off a notchy-wotch? I'll bet it was you, adventurer. Why don'taru you hang around and take on hard mode?
        YOU_RE_ON_FIRE_ADVENTURER_A_RED_HOTARU                                    = 13320,  -- You're on fire, adventurer! A red-hotaru display like that deserves a cool, cool prize. Here you go!
        HEY_DID_YOU_SEE_THE_SHOW_BEING_HELD                                       = 13321,  -- Hey, did you see the show being held at town square?
        THE_SENSATIONAL_NEW_STARLET_MUMOR_IS_PERFORMING_YOU                       = 13322,  -- The sensational new starlet, Mumor, is performing! You have to go and cheer her on, kupo!
        THE_SENSATIONAL_NEW_STARLET_UKA_IS_PERFORMING_YOU                         = 13323,  -- The sensational new starlet, Uka, is performing! You have to go and cheer her on, kupo!
        KUPOPO_THE_BATHING_SUIT_YOU_RE_WEARING_IT                                 = 13324,  -- Kupopo!? The bathing suit you're wearing...it's a prize from the show!
        KUPOPO_THE_YUKATA_YOU_RE_WEARING_IT_S                                     = 13325,  -- Kupopo!? The yukata you're wearing...it's a prize from the show!
        KUPOPO_THE_HAPPI_YOU_RE_WEARING_IT_S                                      = 13326,  -- Kupopo!? The happi you're wearing...it's a prize from the show!
        THE_OUTFIT_YOU_RE_WEARING_IT_S_A                                          = 13327,  -- The outfit you're wearing...it's a prize from the show!
        THANK_YOU_SO_MUCH_FOR_HELPING_OUT_OUR                                     = 13328,  -- Thank you so much for helping out our Mumor, kupo.
        THANK_YOU_SO_MUCH_FOR_HELPING_OUT_OUR_2                                   = 13329,  -- Thank you so much for helping out our Uka, kupo.
        TO_SHOW_OUR_APPRECIATION_I_LL_WARP_YOU                                    = 13330,  -- To show our appreciation, I'll warp you to one of the other nations, kupo! Where do you want to go?
        WHERE_WILL_YOU_GO_NOWHERE_SAN_D_ORIA                                      = 13331,  -- Where will you go? Nowhere. San d'Oria. Bastok. Windurst.
        ENJOY_YOUR_TRIP_KUPO                                                      = 13332,  -- Enjoy your trip, kupo!
        KUPOPO_IS_THAT_A_WIND_CHARM_YOU_HAVE                                      = 13333,  -- Kupopo!? Is that a wind charm you have there?
        LOOKS_LIKE_YOU_VE_REALLY_GOTTEN_INTO_THE                                  = 13334,  -- Looks like you've really gotten into the spirit of the Sunbreeze Festival, kupo!
        AS_A_SHOW_OF_APPRECIATION_I_LL_TELEPORT                                   = 13335,  -- As a show of appreciation, I'll teleport you to one of the other nations! Tell me where you'd like to go, kupo.
        GREETINGS_AND_WELL_MET_GUARDIAN_OF_THE_KINGDOM                            = 13336,  -- Greetings and well met! Guardian of the Kingdom, Alaune, at your most humble service.
        GREETINGS_AND_WELL_MET_DEFENDER_OF_THE_REPUBLIC                           = 13337,  -- Greetings and well met! Defender of the Republic, Gulldago, at your most humble service.
        GREETINGS_AND_WELL_MET_PROTECTOR_OF_THE_FEDERATION                        = 13338,  -- Greetings and well met! Protector of the Federation, Selele, at your most humble service.
        MY_STATION_IS_TO_HELP_ALONG_THOSE_NEW                                     = 13339,  -- My station is to help along those new to the life of an adventurer in Vana'diel. I specialize in the types of fundamental knowledge necessary for success in such endeavors, as well as related methods of pedagogy. With my aid, you can rest assured that your first steps down the adventurer's path will not go astray.
        SHOULD_YOU_STILL_CONSIDER_YOURSELF_A_NEWCOMER_I                           = 13340,  -- Should you still consider yourself a newcomer, I would highly recommend that you make full use of my services.
        THIS_IS_MY_PERMANENT_POST_AND_I_NEVER                                     = 13341,  -- This is my permanent post, and I never leave it. Remember it well. Whenever you need a hand with anything, anything at all, don't hesitate to come calling.
        SO_ARE_YOU_INTERESTED_IN_SOME_ENTRY_LEVEL                                 = 13342,  -- So, are you interested in some entry-level duties to put you well on your way to greatness? Not to worry, I've got just the thing for you!
        GO_TALK_TO_THE_GUARD_ARAVOGE_JUST_OVER                                    = 13343,  -- Go talk to the guard Aravoge just over yonder and have him cast Signet on you. Then come back and see me.
        GO_TALK_TO_THE_GUARD_RABID_WOLF_OVER                                      = 13344,  -- Go talk to the guard Rabid Wolf over yonder and have him cast Signet on you. Then come back and see me.
        GO_TALK_TO_THE_GUARD_HARARA_OVER_YONDER                                   = 13345,  -- Go talk to the guard Harara over yonder and have her cast Signet on you. Then come back and see me.
        WELL_IT_LOOKS_LIKE_YOU_WERE_ABLE_TO                                       = 13346,  -- Well, it looks like you were able to get your Signet. Easy enough, yes?
        AS_LONG_AS_SIGNET_IS_IN_EFFECT_THERE                                      = 13347,  -- As long as Signet is in effect, there is always a possibility that you will obtain crystals from any enemies that you defeat. There are also other more concrete benefits, such as increased defense and evasion.
        SIGNET_EVEN_HELPS_YOU_WHEN_NOT_ENGAGED_IN                                 = 13348,  -- Signet even helps you when not engaged in combat with an enemy. For example, it boosts the rate at which healing occurs while at rest. For all of these reasons and more, you should consider it essential to have Signet cast on you at all times.
        VERY_WELL_THEN_AS_A_REWARD_FOR_SUCCESSFUL                                 = 13349,  -- Very well, then! As a reward for successful completion of your first assignment I would like to present you with these %.
        THERE_IS_MORE_HERE_THAN_MEATS_THE_EYE                                     = 13350,  -- There is more here than meats the eye! That was a joke... Anyway, this is a type of item known amongst adventurers as a meal. This meal in particular will temporarily enhance your attack power when eaten.
        WHENEVER_ANY_TYPE_OF_MEAL_IS_CONSUMED_YOU                                 = 13351,  -- Whenever any type of meal is consumed, you will receive some such temporary status bonus. Naturally, different meals grant different types of bonuses.
        FOR_THE_MOST_PART_MEAT_DISHES_WILL_AFFECT                                 = 13352,  -- For the most part, meat dishes will affect attack power. Conversely, seafood dishes generally enhance defense, and so on and so forth. Take care to select dishes best suited to your purpose.
        ONE_THING_YOU_SHOULD_MAKE_NOTE_OF_HOWEVER                                 = 13353,  -- One thing you should make note of, however, is that you cannot eat a meal while another meal's status bonus is still in effect. Your stomach would simply burst!
        HMMM_THAT_S_QUITE_A_LOT_TO_COVER                                          = 13354,  -- Hmmm, that's quite a lot to cover... Are you with me so far?
        SO_FAR_SO_GOOD_EXPLAIN_SIGNET_AGAIN_EXPLAIN                               = 13355,  -- So far so good? Explain Signet again. Explain meals again. This is a breeze.
        GREAT_WELL_TALKING_CAN_ONLY_PREPARE_YOU_SO                                = 13356,  -- Great! Well, talking can only prepare you so much. Let's get right down to it. Go ahead and pop one of those %!
        AFTER_EATING_A_MEAL_A_STATUS_ICON_DESIGNATED                              = 13357,  -- After eating a meal, a status icon designated as Food will appear in the upper-left portion of your screen. Come back and talk to me again once you've confirmed that it's there.
        CHECK_OUT_THE_FULL_BELLY_ON_YOU_WELL                                      = 13358,  -- Check out the full belly on you! Well done! Signet and meals can both play crucial roles whenever you take on any type of enemy. This is a key lesson that you would do well not to forget!
        NEXT_LET_S_GET_THOSE_PRISTINE_HANDS_OF                                    = 13359,  -- Next, let's get those pristine hands of yours nice and dirty! No sense in letting that food go to waste now, is there? Let's send you out to fight a monster on a full stomach!
        EXITING_THROUGH_THAT_GATE_OVER_THERE_WILL_LEAD                            = 13360,  -- Exiting through that gate over there will lead you into an area with hostile enemies.
        TRY_TO_TARGET_ONE_OF_THE_MONSTERS_AND                                     = 13361,  -- Try to target one of the monsters and then select the Check option from your menu. This will help you ascertain an enemy's level of difficulty and make sure they are not too strong. A smart adventurer picks his/her] fights.
        BE_WARNED_ENGAGING_ANY_ENEMY_THAT_CHECKS_AS                               = 13362,  -- Be warned. Engaging any enemy that checks as very tough or above will result in your Signet not granting you the defense and evasion bonuses you would otherwise receive.
        AND_THAT_BRINGS_US_TO_YOUR_NEXT_ASSIGNMENT                                = 13363,  -- And that brings us to your next assignment!
        IT_S_HIGH_TIME_YOU_LEARNED_HOW_TO                                         = 13364,  -- It's high time you learned how to use a weapon skill!
        PERHAPS_YOU_VE_ALREADY_NOTICED_BUT_SOMETIMES_WHILE                        = 13365,  -- Perhaps you've already noticed, but sometimes while fighting an enemy, your skills will rise little by little.
        WHEN_YOUR_SKILL_WITH_THE_WEAPON_YOU_ARE                                   = 13366,  -- When your skill with the weapon you are wielding reaches a predetermined value, weapon skills will become available for use.
        COMBO_FOR_THOSE_ADEPT_WITH_HAND_TO_HAND                                   = 13367,  -- Combo for those adept with hand-to-hand weapons. Wasp Sting for those who fight with daggers. Fast Blade for those who prefer the sword.
        SHINING_STRIKE_FOR_WIELDERS_OF_THE_CLUB_HEAVY                             = 13368,  -- Shining Strike for wielders of the club. Heavy Swing for those who take up the staff. And on, and on, and on...
        SELECTING_STATUS_FROM_THE_MAIN_MENU_WILL_BRING                            = 13369,  -- Selecting Status from the main menu will bring up the Combat Skl. option. This will display all of the current skill values in all weapon categories.
        THE_FIRST_WEAPON_SKILL_FOR_EACH_WEAPON_TYPE                               = 13370,  -- The first weapon skill for each weapon type can be learned at a skill value of 5. So make that your first goal, and we'll take it from there!
        OHHH_SOMEBODY_WENT_AND_LEARNED_A_NEW_WEAPON                               = 13371,  -- Ohhh! Somebody went and learned a new weapon skill, didn't he/she]? Very good!
        I_CAN_SEE_BY_THAT_TWINKLE_IN_YOUR                                         = 13372,  -- I can see by that twinkle in your eyes that you've already used it on some poor, unfortunate creature, but I'll explain just a bit more. Whenever your Tactical Points (TP) reach 1000 or more, selecting Abilities and then Weapon Skl. from the menu will display a list of usable weapon skills.
        THESE_ARE_DEADLY_TECHNIQUES_CAPABLE_OF_RENDERING_MASSIVE                  = 13373,  -- These are deadly techniques capable of rendering massive damage on enemies. It is well worth an adventurer's time to learn and master them.
        AH_BY_THE_WAY_WERE_YOU_FORTUNATE_ENOUGH                                   = 13374,  -- Ah, by the way, were you fortunate enough to receive some items from the monsters you fought?
        IF_YOU_WERE_LUCKY_ENOUGH_TO_COME_ACROSS                                   = 13375,  -- If you were lucky enough to come across any %, make sure you hang onto them. They may pay dividends later on...
        VERY_WELL_THEN_AS_A_REWARD_FOR_COMPLETING                                 = 13376,  -- Very well then. As a reward for completing your assignment, I present you with # gil.
        BY_THE_WAY_ARE_YOU_FAMILIAR_WITH_GIL                                      = 13377,  -- By the way, are you familiar with gil?
        GIL_IS_THE_UNIVERSAL_CURRENCY_USED_THROUGHOUT_VANA                        = 13378,  -- Gil is the universal currency used throughout Vana'diel. It is used in shops as well as in transactions between adventurers.
        NOT_EVERY_ITEM_CAN_BE_PURCHASED_WITH_GIL                                  = 13379,  -- Not every item can be purchased with gil, but many useful things certainly can.
        EACH_GIL_COIN_BEARS_AN_ARCANE_WATERMARK_TO                                = 13380,  -- Each gil coin bears an arcane watermark to prevent forgery. Tampering with currency could invite divine punishment, so do take care.
        NOW_THEN_THE_NEXT_THING_I_WANT_YOU                                        = 13381,  -- Now then, the next thing I want you to learn is something every modern adventurer must know. It is called Records of Eminence.
        FIRST_OPEN_THE_QUEST_MENU_YOU_CAN_FIND                                    = 13382,  -- First, open the Quest menu. You can find it by selecting Main Menu, and then choosing Quests.
        FROM_THERE_CHOOSE_RECORDS_OF_EMINENCE_SELECT_OBJECTIVE                    = 13383,  -- From there, choose Records of Eminence, select Objective List, and then navigate to Tutorial, followed by Basics, and finally First Step Forward.
        WHEN_FIRST_STEP_FORWARD_OPENS_YOU_WILL_BE                                 = 13384,  -- When First Step Forward opens, you will be asked whether you want to set it as an objective. Select Yes to make it your active objective.
        ONCE_THAT_S_DONE_SPEAK_WITH_ROLANDIENNE_WHO                               = 13385,  -- Once that's done, speak with Rolandienne, who stands directly in front of me.
        NEXT_SPEAK_WITH_ISAKOTH_WHO_STANDS_JUST_TO                                = 13386,  -- Next, speak with Isakoth, who stands just to my forward right.
        AFTER_THAT_SPEAK_WITH_FHELM_JOBEIZAT_WHO_STANDS                           = 13387,  -- After that, speak with Fhelm Jobeizat, who stands to my front left.
        FURTHER_DETAILS_ABOUT_RECORDS_OF_EMINENCE_ARE_HANDLED                     = 13388,  -- Further details about Records of Eminence are handled by the specialist. Once you've received the explanation, return to me.
        IT_SEEMS_YOU_VE_RECEIVED_THE_EXPLANATION_REGARDING                        = 13389,  -- It seems you've received the explanation regarding Records of Eminence.
        COMPLETING_OBJECTIVES_EARNS_YOU_EXPERIENCE_POINTS_AS_WELL                 = 13390,  -- Completing objectives earns you experience points as well as sparks of eminence. Experience helps you level more efficiently, while sparks of eminence can be exchanged for equipment.
        MY_RECOMMENDED_OBJECTIVES_ARE_FOUND_UNDER_COMBAT_WIDE                     = 13391,  -- My recommended objectives are found under Combat (Wide Area), within Combat (Spoils) 1. Start with Spoils (Fire Crystal), and continue through Spoils (Water Crystal).
        THESE_SETTINGS_MIGHT_AS_WELL_REMAIN_IN_PLACE                              = 13392,  -- These settings might as well remain in place at all times.
        AS_YOU_CONTINUE_ADVENTURING_YOU_LL_OFTEN_OBTAIN                           = 13393,  -- As you continue adventuring, you'll often obtain items such as % or % as spoils.
        IF_YOU_VE_SET_THE_RECOMMENDED_OBJECTIVES_YOUR                             = 13394,  -- If you've set the recommended objectives, your progress will advance automatically, and you'll complete them once you obtain the required number of crystals.
        THERE_ARE_MANY_OBJECTIVES_THAT_PROGRESS_NATURALLY_AS                      = 13395,  -- There are many objectives that progress naturally as you adventure. Try setting various goals, and you may be surprised at how many benefits you gain at once.
        ALSO_THAT_REMINDS_ME_THERE_IS_ANOTHER_LESSON                              = 13396,  -- Also, that reminds me. There is another lesson better learned sooner than later. The items you will no doubt come across known as crystals.
        THEY_ARE_TRULY_VERSATILE_ITEMS_THAT_CAN_BE                                = 13397,  -- They are truly versatile items that can be used for a number of purposes. These include trading them to guards for certain rewards, and selling them to earn money, just to name a few.
        FOR_NOW_I_D_LIKE_TO_EXPLAIN_MORE                                          = 13398,  -- For now, I'd like to explain more about another of their uses. Namely, the role they play in synthesis.
        BUT_FIRST_THINGS_FIRST_YOUR_REWARD_FOR_COMPLETING                         = 13399,  -- But first things first. Your reward for completing your last assignment! Here you are, then. %, %, and last but not least, %.
        NOW_USING_WILL_BRING_UP_THE_SYNTHESIS_INTERFACE                           = 13400,  -- Now, using % will bring up the synthesis interface. Once there, select the % and % as the ingredients to be added.
        ALL_THAT_REMAINS_IS_TO_SELECT_THE_OK                                      = 13401,  -- All that remains is to select the OK option, and the synthesis will commence!
        YOU_LL_FIND_THAT_THE_CRAFTING_PROCESS_WILL                                = 13402,  -- You'll find that the crafting process will never begin, should the ingredients you've selected not form a viable synthesis recipe. Also, even when your materials are correct, there is always a chance that your synthesis will fail, so please be wary.
        THE_MAJORITY_OF_ITEMS_WHICH_YOU_CREATE_VIA                                = 13403,  -- The majority of items which you create via synthesis, as well as most of those dropped by enemies you defeat, can be placed on the auction house for sale.
        THE_AUCTION_HOUSE_IS_AN_ULTRA_CONSUMER_VENUE                              = 13404,  -- The auction house is an ultra-consumer venue where you can attempt to purchase the wares of other players by placing bids, as well as have other players bid on items you have put up for sale.
        MY_WORDS_ALONE_CAN_DO_NO_JUSTICE_TO                                       = 13405,  -- My words alone can do no justice to the vast cornucopia of goods that is the auction house. One simply must see it with one's own eyes.
        ARE_YOU_STILL_WITH_ME_EXPLAIN_RECORDS_OF                                  = 13406,  -- Are you still with me? Explain Records of Eminence again. Explain synthesis again. Explain the auction house again. Sure am.
        SOMEWHERE_IN_THIS_GREAT_CITY_LIES_OUR_NATION                              = 13407,  -- Somewhere in this great city lies our nation's auction house. Seek it out, and report back to me when you have found it.
        THE_AUCTION_HOUSE_CAN_BE_FOUND_HERE_IN                                    = 13408,  -- The auction house can be found here in Southern San d'Oria (I-9) as well as at Port San d'Oria (H-10). Either location will do.
        IN_BASTOK_THE_AUCTION_HOUSE_IS_LOCATED_IN                                 = 13409,  -- In Bastok, the auction house is located in the Markets (E-8) and the Mines (I-8). Either one works.
        IN_WINDURST_THE_AUCTION_HOUSE_IS_FOUND_IN                                 = 13410,  -- In Windurst, the auction house is found in Windurst Woods (J-12) and Windurst Walls (I-11). Either is fine.
        YOU_NEEDN_T_WORRY_ABOUT_GOING_THROUGH_WITH                                = 13411,  -- You needn't worry about going through with an actual purchase. Simply examining any of the Auction Counters will more than suffice.
        SO_YOU_WERE_ABLE_TO_LOCATE_THE_AUCTION                                    = 13412,  -- So, you were able to locate the auction house! Pretty hard to miss, isn't it?
        WHAT_DO_YOU_THINK_IT_IS_AS_I                                              = 13413,  -- What do you think? It is as I said, yes? Few organizations in this world exceed the auction house in scale. It will never cease to be of use to you throughout your adventures. It would be wise to become adept at using it.
        AND_NOW_DOWN_TO_BRASS_TACKS_LET_S                                         = 13414,  -- And now down to brass tacks! Let's see if we can't get you to up some levels!
        THERE_ARE_SEVERAL_ITEMS_IN_EXISTENCE_WHICH_SERVE                          = 13415,  -- There are several items in existence which serve to enhance the number of experience points you receive for defeating enemies.
        FOR_EXAMPLE_THERE_ARE_AND_JUST_TO_NAME                                    = 13416,  -- For example, there are %, %, and %, just to name a few.
        THESE_ARE_A_BIT_UNIQUE_IN_THAT_YOU                                        = 13417,  -- These are a bit unique in that you must wait a certain amount of time after equipping them before you may use them.
        THERE_IS_ALSO_A_PREDETERMINED_AMOUNT_OF_TIME                              = 13418,  -- There is also a predetermined amount of time, usually quite long, that must pass before these items can be used again. The total number of times you may use any single item is also limited, so be mindful of that as well.
        MANY_OF_THESE_ITEMS_MAY_BE_OBTAINED_FROM                                  = 13419,  -- Many of these items may be obtained from the same guards that provide you with Signet. You need only exchange conquest points in order to acquire them.
        AS_A_MATTER_OF_FACT_FOR_FINISHING_THAT                                    = 13420,  -- As a matter of fact, for finishing that last assignment, I'm going to give you this %. With this, you'll be able to obtain % without having to use any of your conquest points.
        NOW_THEN_ADVENTURER_RAISE_YOUR_LEVEL_TO_5                                 = 13421,  -- Now then, adventurer, raise your level to 5 and return to me.
        WITH_AN_EXPERIENCE_BONUS_IN_PLACE_IT_SHOULD                               = 13422,  -- With an experience bonus in place, it should take you practically no time at all. Good luck, and be careful! It can get quite hairy out there!
        WELL_WELL_WELL_WE_MIGHT_MAKE_AN_ADVENTURER                                = 13423,  -- Well, well, well! We might make an adventurer out of you just yet! Looks like we've almost washed all that green off of you.
        A_BIT_OF_BAD_NEWS_NOW_THOUGH_STARTING                                     = 13424,  -- A bit of bad news now, though. Starting from level 31, anytime you are knocked unconscious your experience points will suffer a deduction.
        AS_A_GENERAL_RULE_THE_AMOUNT_PENALIZED_WILL                               = 13425,  -- As a general rule, the amount penalized will be about 10% of the total amount required to reach the next level. You have to be more careful than ever from here on out!
        HOWEVER_THERE_ARE_WAYS_TO_MINIMIZE_THIS_LOSS                              = 13426,  -- However, there are ways to minimize this loss of experience points.
        LIKE_THIS_FOR_EXAMPLE_GO_ON_TAKE_IT                                       = 13427,  -- Like this, for example. Go on, take it. Your reward for completing the previous assignment. It's called %.
        USING_THIS_WILL_GRANT_YOU_A_STATUS_KNOWN                                  = 13428,  -- Using this will grant you a status known as Reraise. Whenever you are rendered unconscious while this effect is in place, you will have the option to revive yourself.
        CHOOSING_TO_DO_SO_WILL_CAUSE_YOU_TO                                       = 13429,  -- Choosing to do so will cause you to be resuscitated in the very spot where you have fallen. In addition, as I stated previously, the amount of experience points you lose will be somewhat lessened.
        HOWEVER_AFTER_BEING_REVIVED_YOU_WILL_SUFFER_FROM                          = 13430,  -- However, after being revived, you will suffer from the status ailment Weakness. For a certain period of time, your maximum HP and maximum MP will drop sharply, and both your attack interval and spell recast times will become much longer.
        WEAKNESS_WILL_FADE_ON_ITS_OWN_AFTER_SOME                                  = 13431,  -- Weakness will fade on its own after some time, so remain calm and move to a safe location until it wears off.
        AND_SIMILAR_ITEMS_WORK_IN_THE_SAME_MANNER                                 = 13432,  -- % and similar items work in the same manner as the % and the other experience bonus items I mentioned earlier. That is, once equipped, you must wait a certain period of time before they can be used, and there are both cooldown timers and limited charges as well.
        ALL_OF_THESE_ITEMS_AS_A_WHOLE_ARE                                         = 13433,  -- All of these items as a whole are collectively referred to as enchanted items. There is a vast array of other enchanted items with myriad other effects that will prove useful on your adventures. It may be worth the time and effort to better acquaint yourself with them at some point.
        ANY_QUESTIONS_ABOUT_BEING_KO_D_ABOUT_ENCHANTED                            = 13434,  -- Any questions? About being KO'd. About enchanted items. None for now.
        NOW_THAT_YOU_HAVE_SURPASSED_THE_REQUIRED_LEVEL                            = 13435,  -- Now that you have surpassed the required level, it is time for you to learn a new spell called Trust. That will be your next assignment.
        A_TRUST_SPELL_ALLOWS_YOU_TO_SUMMON_AN                                     = 13436,  -- A Trust spell allows you to summon an alter ego, an echo of someone in this world, to fight at your side. This magic will surely become a dependable companion in your adventures.
        THERE_IS_A_DEDICATED_INSTRUCTOR_FOR_TRUST_MAGIC                           = 13437,  -- There is a dedicated instructor for Trust magic. Head to the person I'm about to tell you about.
        IN_SAN_D_ORIA_TRUST_MAGIC_INSTRUCTION_IS                                  = 13438,  -- In San d'Oria, Trust magic instruction is handled by Gondebaud, found here in Southern San d'Oria (L-6). He's the Elvaan wearing green attire and a matching hat.
        IN_BASTOK_CLARION_STAR_HANDLES_TRUST_MAGIC_INSTRUCTION                    = 13439,  -- In Bastok, Clarion Star handles Trust magic instruction. You'll find this Galka at Port Bastok (K-7), wearing green garments.
        IN_WINDURST_WETATA_PROVIDES_TRUST_MAGIC_INSTRUCTION_YOU                   = 13440,  -- In Windurst, Wetata provides Trust magic instruction. You can find this Tarutaru in Windurst Woods (G-10), dressed in green.
        THE_DESTINATION_MAY_BE_A_BIT_OF_A                                         = 13441,  -- The destination may be a bit of a walk. Tell me, do you know how to read your map? Open it through Main Menu, followed by Map, and check the coordinates displayed along the edges.
        ONCE_YOU_VE_UNLOCKED_TRUST_MAGIC_AND_RECEIVED                             = 13442,  -- Once you've unlocked Trust magic and received %, return to me.
        CONGRATULATIONS_IT_LOOKS_LIKE_YOU_VE_SAFELY_OBTAINED                      = 13443,  -- Congratulations! It looks like you've safely obtained your Trust permit.
        AS_YOU_CONTINUE_YOUR_JOURNEY_YOU_LL_BE                                    = 13444,  -- As you continue your journey, you'll be able to summon stronger companions and even expand the number you can call forth. Keep striving onward.
        AND_ONE_MORE_THING_IF_YOU_HAPPEN_TO                                       = 13445,  -- And one more thing. If you happen to obtain a scroll known as a cipher, you should take it to the official in green who explained Trust magic to you earlier.
        BY_USING_A_CIPHER_YOU_WILL_BE_ABLE                                        = 13446,  -- By using a cipher, you will be able to call forth the person whose name is written on it as a new alter ego.
        WHEN_YOU_COMPLETE_THE_RECORDS_OF_EMINENCE_OBJECTIVE                       = 13447,  -- When you complete the Records of Eminence objective found under Tutorial, within Basics, called Call Forth an Alter Ego, you will receive a cipher as a special reward. Be sure to give it a try.
        AND_NOW_AS_A_REWARD_FOR_COMPLETING_THESE                                  = 13448,  -- And now, as a reward for completing these tasks, I present you with %.
        THIS_IS_ALSO_AN_ENCHANTED_ITEM_WHEN_YOU                                   = 13449,  -- This % is also an enchanted item. When you equip and use it, the spell Warp shall whisk you back to your Home Point.
        WARP_IS_A_SPELL_THAT_RETURNS_YOU_INSTANTLY                                = 13450,  -- Warp is a spell that returns you instantly to your Home Point.
        A_HOME_POINT_IS_ONE_OF_THE_MANY                                           = 13451,  -- A Home Point is one of the many blue crystalline monuments found throughout the land.
        IF_YOU_EXAMINE_A_HOME_POINT_AND_SET                                       = 13452,  -- If you examine a Home Point and set the option Set Home Point, you will be able to return there whether you use Warp or find yourself felled in battle.
        ALSO_ONCE_YOU_HAVE_EXAMINED_A_HOME_POINT                                  = 13453,  -- Also, once you have examined a Home Point before, you can warp to it from another Home Point.
        AS_ANOTHER_WARP_METHOD_THERE_IS_A_TELEPORTATION                           = 13454,  -- As another warp method, there is a teleportation device called the Survival Guide.
        A_SURVIVAL_GUIDE_APPEARS_AS_AN_OPEN_BOOK                                  = 13455,  -- A Survival Guide appears as an open book and sways up and down.
        YOU_CAN_ALSO_WARP_BETWEEN_SURVIVAL_GUIDES_YOU                             = 13456,  -- You can also warp between Survival Guides you have previously examined.
        ARE_YOU_FOLLOWING_SO_FAR_TELL_ME_ABOUT                                    = 13457,  -- Are you following so far? Tell me about Trust again. Tell me about the % again. Tell me about Home Points again. Tell me about Survival Guides again. I'll keep it in mind.
        YOUR_NEXT_TASK_IS_TO_EXPERIENCE_WARPING_USING                             = 13458,  -- Your next task is to experience warping using the Survival Guide I explained earlier.
        FIRST_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN_NORTHERN                      = 13459,  -- First, examine the Survival Guide located in Northern San d'Oria (E-8).
        FIRST_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN_THE                           = 13460,  -- First, examine the Survival Guide located in the Bastok Mines (I-9).
        FIRST_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN_PORT                          = 13461,  -- First, examine the Survival Guide located in Port Windurst (B-5).
        AFTER_THAT_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN                          = 13462,  -- After that, examine the Survival Guide located in West Ronfaure (G-9). Then choose Teleportation Assistance and return to Northern San d'Oria.
        AFTER_THAT_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN_2                        = 13463,  -- After that, examine the Survival Guide located in North Gustaberg (D-10). Then choose Teleportation Assistance and return to the Bastok Mines.
        AFTER_THAT_EXAMINE_THE_SURVIVAL_GUIDE_LOCATED_IN_3                        = 13464,  -- After that, examine the Survival Guide located in West Sarutabaruta (H-6). Then choose Teleportation Assistance and return to Windurst Port.
        AFTER_RETURNING_TO_TOWN_USE_THE_AND_COME                                  = 13465,  -- After returning to town, use the % and come back to me. That will complete your task.
        AH_DON_T_FORGET_TO_SET_YOUR_HOME                                          = 13466,  -- Ah, don't forget to set your Home Point at the Home Point located to my [right/front/left] before using the %.
        IT_LOOKS_LIKE_YOU_SUCCESSFULLY_EXPERIENCED_WARPING                        = 13467,  -- It looks like you successfully experienced warping.
        WARPING_IS_A_VERY_USEFUL_METHOD_OF_TRANSPORTATION                         = 13468,  -- Warping is a very useful method of transportation in this vast world of Vana'diel. Make good use of it.
        TO_INCREASE_YOUR_AVAILABLE_WARP_DESTINATIONS_I_RECOMMEND                  = 13469,  -- To increase your available warp destinations, I recommend examining any Home Points or Survival Guides you come across.
        NOW_THEN_IT_SEEMS_WE_ARE_NEARING_THE                                      = 13470,  -- Now then, it seems we are nearing the end of my guidance for adventurers.
        YOUR_NEXT_ASSIGNMENT_IS_TO_WORK_YOUR_WAY                                  = 13471,  -- Your next assignment is to work your way up to level 18.
        MAKE_USE_OF_DEFEATING_MONSTERS_PARTICIPATING_IN_RECORDS                   = 13472,  -- Make use of defeating monsters, participating in Records of Eminence, and using alter egos as I have taught you, and give it a try.
        AS_YOU_DEFEAT_MONSTERS_IN_THE_AREAS_AROUND                                = 13473,  -- As you defeat monsters in the areas around town, you may notice that they no longer pose much of a challenge.
        IF_YOU_ARE_SEVERAL_LEVELS_BEYOND_A_MONSTER                                = 13474,  -- If you are several levels beyond a monster and totally outclass them in every respect, checking them will yield a too weak to be worthwhile result.
        KILLING_MONSTERS_SO_FAR_BENEATH_YOU_IS_BORDERLINE                         = 13475,  -- Killing monsters so far beneath you is borderline cowardice, and will net you no experience points.
        IF_YOU_START_TO_NOTICE_MORE_AND_MORE                                      = 13476,  -- If you start to notice more and more of these too weak monsters around you, consider moving farther from the city to a more difficult area.
        TO_THE_OF_YOU_WILL_FIND_THE                                               = 13477,  -- To the [south/north/north] of [West Ronfaure/North Gustaberg/East Sarutabaruta], you will find the [La Theine Plateau/Konschtat Highlands/Tahrongi Canyon].
        FURTHERMORE_TO_THE_OF_THE_YOU_WILL_FIND                                   = 13478,  -- Furthermore, to the [south/north/east] of the [La Theine Plateau/Konschtat Highlands/Tahrongi Canyon], you will find the [Valkurm Dunes/Valkurm Dunes/Buburimu Peninsula].
        JUST_KEEP_IN_MIND_THE_FARTHER_YOU_STRAY                                   = 13479,  -- Just keep in mind, the farther you stray from the city, the more ferocious monsters tend to be. Don't say I didn't warn you.
        MAKE_SURE_TO_USE_THE_CHECK_COMMAND_TO                                     = 13480,  -- Make sure to use the Check command to determine the strength of your enemy. If you find that you are surrounded by enemies too difficult for you, try heading back to a previous area closer to the city and leveling up a bit more first.
        BY_THE_TIME_YOU_REACH_LEVEL_18_THE                                        = 13481,  -- By the time you reach level 18, the monsters around the entrance to the [Valkurm Dunes/Valkurm Dunes/Buburimu Peninsula] should be an appropriate challenge for you.
        ALSO_REMEMBER_NOT_ONLY_TO_LEVEL_UP_BUT                                    = 13482,  -- Also, remember not only to level up, but to work on increasing your skills as I explained earlier.
        BY_LEVEL_18_YOU_SHOULD_BE_ABLE_TO                                         = 13483,  -- By level 18, you should be able to learn one or two additional weapon skills.
        FURTHERMORE_AS_YOUR_WEAPON_SKILL_LEVEL_INCREASES_YOUR                     = 13484,  -- Furthermore, as your weapon skill level increases, your attack power and accuracy will also increase.
        HOWEVER_RAISING_SKILLS_CAN_BE_QUITE_DIFFICULT_SO                          = 13485,  -- However, raising skills can be quite difficult. So, as a reward for completing the previous task, I will present you with %.
        THE_INCREASES_THE_RATE_AT_WHICH_YOUR_SKILLS                               = 13486,  -- The % increases the rate at which your skills improve through the effect of food. Simply fighting blindly will not work. Increase your knowledge and fight using your head.
        BUT_DON_T_GO_GETTING_TOO_COCKY_THIS                                       = 13487,  -- But don't go getting too cocky! This world is chock-full of monsters just waiting for the opportune moment to pounce and knock you out cold!
        DEPENDING_ON_THE_TYPE_OF_MONSTER_THERE_ARE                                = 13488,  -- Depending on the type of monster, there are several factors that could cause them to attack you without provocation. I'll enumerate some of the more common types of this blatantly aggressive behavior for you.
        FOR_STARTERS_AND_MOST_OBVIOUSLY_THERE_ARE_MONSTERS                        = 13489,  -- For starters, and most obviously, there are monsters which detect by sight. They will attack you whenever you enter their field of vision. This is the most prevalent type. They simply cannot stand the sight of adventurers.
        NEXT_THERE_ARE_THOSE_MONSTERS_WHICH_DETECT_BY                             = 13490,  -- Next, there are those monsters which detect by sound. They can be a bit more dangerous than visually-dependent monsters, in that they will attack the source of any sound within a certain prescribed radius. You may not think it, but there are a great many monsters whose aural senses are far more developed than their sense of sight.
        THERE_ARE_ALSO_MONSTERS_WHICH_DETECT_THEIR_ENEMIES                        = 13491,  -- There are also monsters which detect their enemies' spellcasting. Much like the sound-detecting types, these monsters will attack the source of any magic casting within a certain radius of their being. Not surprisingly, many monsters in the arcana family rely heavily on this method of detection, which covers a comparatively larger range than the aforementioned sense of hearing.
        AND_FINALLY_THERE_ARE_OPPORTUNISTIC_MONSTERS_WHICH_PREY                   = 13492,  -- And finally, there are opportunistic monsters which prey upon the weak and near-dead, pinpointing their prey by detecting low hit points. The family of undead creatures abound in monsters of this type. Even more distressing, the fewer the hit points you have, the farther the distance from which you can be detected.
        IS_ALL_CLEAR_SO_FAR_TELL_ME_ABOUT                                         = 13493,  -- Is all clear so far? Tell me about leveling areas again. Tell me about skills again. Tell me about detection again. Right then.
        WELL_THEN_DO_YOUR_BEST_AND_AIM_FOR                                        = 13494,  -- Well then, do your best and aim for level 18.
        SIGNET_FOOD_CHECKING_MONSTERS_LEVELING_AND_SKILLS_RECORDS                 = 13495,  -- Signet, food, checking monsters, leveling and skills, Records of Eminence, experience-bonus enchanted items, Trust, and warping.
        LET_ME_SEE_HOW_WELL_YOU_VE_ABSORBED                                       = 13496,  -- Let me see how well you've absorbed all of these.
        EXCELLENT_YOU_VE_SUCCESSFULLY_SURPASSED_LEVEL_18                          = 13497,  -- Excellent! You've successfully surpassed level 18.
        HOW_DID_YOU_LIKE_THE_AREAS_YOU_STEPPED                                    = 13498,  -- How did you like the areas you stepped into for the first time? I imagine they were quite exciting.
        YES_YES_THAT_IS_WHAT_BEING_AN_ADVENTURER                                  = 13499,  -- Yes, yes, that is what being an adventurer is all about.
        TELL_ME_DID_YOU_VISIT_THE                                                 = 13500,  -- Tell me, did you visit the [La Theine Plateau/Konschtat Highlands/Tahrongi Canyon]?
        AROUND_THE_CENTRAL_AREA_YOU_SHOULD_HAVE_SEEN                              = 13501,  -- Around the central area, you should have seen a large white structure, the place marked on the map as [Crag of Holla/Crag of Dem/Crag of Mea].
        THERE_YOU_WILL_FIND_A_HUGE_CRYSTAL_CALLED                                 = 13502,  -- There you will find a huge crystal called a Telepoint. By examining it, you can obtain %.
        AND_NOW_FOR_SOME_INFORMATION_REGARDING_THIS_LITTLE                        = 13503,  -- And now for some information regarding this little beauty. As long as you have this %, you will be able to be transported by the appropriate spell of teleportation directly to the telepoint from which you retrieved it.
        I_DOUBT_THAT_YOU_WILL_HAVE_MANY_OPPORTUNITIES                             = 13504,  -- I doubt that you will have many opportunities to use it for the time being, but you would do well to remember what I have said.
        SEVERAL_SUCH_TELEPOINTS_EXIST_SCATTERED_THROUGHOUT_VANA_DIEL              = 13505,  -- Several such telepoints exist, scattered throughout Vana'diel. Each has its own specific gate crystal, which you will receive the first time that you examine any of them.
        NOW_THEN_AS_A_REWARD_FOR_COMPLETING_THIS                                  = 13506,  -- Now then, as a reward for completing this task, I present you with %.
        HAVE_YOU_EVER_COME_ACROSS_BEFORE                                          = 13507,  -- Have you ever come across % before?
        AS_I_EXPLAINED_EARLIER_YOU_CAN_DEPOSIT_IT                                 = 13508,  -- As I explained earlier, you can deposit it by Trading it to the Records of Eminence representative.
        AFTER_YOU_HAVE_ENTRUSTED_IT_SPEAK_TO_THE                                  = 13509,  -- After you have entrusted it, speak to the representative again. From the option Exchange A.M.A.N. Currencies, you will be able to choose Currencies.
        COPPER_A_M_A_N_VOUCHERS_CAN_BE                                            = 13510,  -- Copper A.M.A.N. vouchers can be exchanged for various currencies, including sparks of eminence, but for now it is enough simply to know that.
        WHAT_IS_IMPORTANT_RIGHT_NOW_IS_THAT_YOU                                   = 13511,  -- What is important right now is that you can obtain sparks of eminence from copper A.M.A.N. vouchers.
        ONCE_YOU_VE_EARNED_SOME_SPARKS_OF_EMINENCE                                = 13512,  -- Once you've earned some sparks of eminence, I recommend exchanging it for equipment suitable for your current level.
        EVEN_IF_YOU_RAISE_ONLY_YOUR_LEVEL_WITHOUT                                 = 13513,  -- Even if you raise only your level, without proper equipment, you cannot call yourself a strong adventurer.
        HOW_ARE_YOU_DOING_SO_FAR_TELL_ME                                          = 13514,  -- How are you doing so far? Tell me about Telepoints again. Tell me about %. Very well.
        WELL_THEN_THIS_WILL_BE_YOUR_FINAL_ASSIGNMENT                              = 13515,  -- Well then, this will be your final assignment.
        FOR_THE_LAST_ASSIGNMENT_I_WANT_YOU_TO                                     = 13516,  -- For the last assignment, I want you to obtain your Support Job.
        THERE_ARE_SEVERAL_WAYS_TO_ACQUIRE_IT_SO                                   = 13517,  -- There are several ways to acquire it, so you may choose whichever method you prefer.
        GATHERING_THE_INFORMATION_NEEDED_TO_ACHIEVE_YOUR_GOAL                     = 13518,  -- Gathering the information needed to achieve your goal, collecting the knowledge required to move forward, is also an important skill for adventurers.
        THAT_SAID_SUDDENLY_LEAVING_YOU_COMPLETELY_ON_YOUR                         = 13519,  -- That said, suddenly leaving you completely on your own would be a bit too harsh.
        LET_ME_GIVE_YOU_A_HINT_YOU_CAN                                            = 13520,  -- Let me give you a hint. You can find a town called [Selbina/Selbina/Mhaura] in the [Valkurm Dunes/Valkurm Dunes/Buburimu Peninsula].
        ONCE_YOU_ARE_ABLE_TO_SET_YOUR_SUPPORT                                     = 13521,  -- Once you are able to set your Support Job, return to me. I wish you the best of luck!
        SPLENDID_YOU_VE_SUCCESSFULLY_OBTAINED_YOUR_SUPPORT_JOB                    = 13522,  -- Splendid! You've successfully obtained your Support Job!
        FROM_NOW_ON_YOU_MAY_SET_A_SUPPORT                                         = 13523,  -- From now on, you may set a Support Job to enhance your Main Job's abilities, or broaden your tactical options during battle.
        EXPERIMENT_WITH_DIFFERENT_COMBINATIONS_AND_DISCOVER_THE_SETUP             = 13524,  -- Experiment with different combinations and discover the setup that suits you best. The possibilities are endless.
        LET_ME_TAKE_THIS_TIME_TO_OFFER_YOU                                        = 13525,  -- Let me take this time to offer you a most heartfelt congratulations, %! You have successfully completed all of the assignments I have laid before you.
        AND_HERE_I_HAVE_A_MOST_FITTING_REWARD                                     = 13526,  -- And here I have a most fitting reward for you. A gift of % and # %.
        THE_IS_AN_ENCHANTED_ITEM_WITH_UNLIMITED_USES                              = 13527,  -- The % is an enchanted item with unlimited uses that grants an experience point bonus.
        IF_THE_ITEM_DESCRIPTION_SHOWS_CHARGES_MAX_CHARGES                         = 13528,  -- If the item description shows Charges / Max Charges as 1/1, it means the remaining uses never drop to zero. In other words, you can use it indefinitely, so keep that in mind.
        THE_IS_A_TRIAL_CHOCOBO_LICENSE_THAT_LETS                                  = 13529,  -- The % is a trial chocobo license that lets you ride a chocobo. It can be used at a chocobo stable, but keep in mind the riding time is short.
        I_FEAR_THAT_I_HAVE_NOTHING_MORE_TO                                        = 13530,  -- I fear that I have nothing more to teach you. From now on, your lessons will best be learned by giving a mindful ear to others and being ever observant on your travels.
        DO_REMEMBER_THOUGH_THAT_THE_PATHS_OPEN_BEFORE                             = 13531,  -- Do remember, though, that the paths open before you will multiply greatly should you cooperate with other adventurers.
        LEVELING_FOR_EXAMPLE_IS_AN_ENDEAVOR_MADE_IMMEASURABLY                     = 13532,  -- Leveling, for example, is an endeavor made immeasurably more efficient and enjoyable in the company of others. It helps to not only guarantee you some modicum of safety in numbers, but also rewards you with considerably more experience points than adventuring alone.
        AND_WHEN_FACING_FORMIDABLE_ENEMIES_FORMING_A_PARTY                        = 13533,  -- And when facing formidable enemies, forming a party can expand your tactical options and allow you to defeat foes far stronger than those you could handle alone or with alter egos.
        I_SUPPOSE_IT_DOES_REQUIRE_A_GOOD_DEAL                                     = 13534,  -- I suppose it does require a good deal of courage to approach an adventurer you do not know, but I strongly encourage you to do so. It may prove to be the beginning of an extremely rewarding and long-lasting friendship.
        THERE_MAY_STILL_BE_SOME_SMALL_FACETS_OF                                   = 13535,  -- There may still be some small facets of adventuring that I can continue to offer you advice on. Should you ever have any questions or anxieties, please do not hesitate to come and see me again. I will do my best to be of service and set your heart at ease.
        GO_NOW_AND_GO_WELL_THE_WORLD_AWAITS                                       = 13536,  -- Go now, and go well. The world awaits its next great adventurer, %.
        GOOD_DAY_TO_YOU_GUARDIAN_OF_THE_KINGDOM                                   = 13537,  -- Good day to you! Guardian of the Kingdom, Alaune, at your most humble service. Is there something in particular I can help you with this day?
        GOOD_DAY_TO_YOU_DEFENDER_OF_THE_REPUBLIC                                  = 13538,  -- Good day to you! Defender of the Republic, Gulldago, at your most humble service. Is there something in particular I can help you with this day?
        GOOD_DAY_TO_YOU_PROTECTOR_OF_THE_FEDERATION                               = 13539,  -- Good day to you! Protector of the Federation, Selele, at your most humble service. Is there something in particular I can help you with this day?
        WHAT_WILL_YOU_ASK_ABOUT_NOTHING_JUST_NOW                                  = 13540,  -- What will you ask about? Nothing just now. Search comments. Skillchains. Magic bursts. Skillchains and elements.
        JUST_AS_THEIR_NAME_IMPLIES_SEARCH_COMMENTS_ARE                            = 13541,  -- Just as their name implies, search comments are original messages composed by adventurers which are readily visible to others when using the search function.
        THERE_ARE_SEVERAL_DIFFERENT_CATEGORIES_OF_SEARCH_COMMENTS                 = 13542,  -- There are several different categories of search comments. These include, but are not limited to, EXP Party, Items, and Missions and Quests.
        OPENING_THE_SEARCH_FUNCTION_FROM_THE_MAIN_MENU                            = 13543,  -- Opening the Search function from the Main Menu and then selecting the Comment option will allow you to conduct a player search by comment type.
        FOR_EXAMPLE_IF_YOU_WOULD_LIKE_TO_SEARCH                                   = 13544,  -- For example, if you would like to search for other players to form a leveling party, you need only select EXP Party from the list displayed.
        OF_COURSE_SEARCH_COMMENT_COMPOSITION_DIFFERS_FROM_PERSON                  = 13545,  -- Of course, search comment composition differs from person to person. You might want to conduct a search first to see what type of search comments are considered the norm before writing your own.
        SKILLCHAINS_ARE_DEVASTATING_ELEMENTAL_PHENOMENA_WHICH_MANIFEST_THEMSELVES = 13546,  -- Skillchains are devastating elemental phenomena which manifest themselves when weapon skills are carried out in a precise and well-timed order.
        THE_VERY_NATURES_OF_THE_SKILLCHAINS_THEMSELVES_DIFFER                     = 13547,  -- The very natures of the skillchains themselves differ widely, being dependent upon the weapon skills used and the order of their execution.
        TO_TAKE_A_SIMPLE_AND_TIMELESS_EXAMPLE_USING                               = 13548,  -- To take a simple and timeless example, using the weapon skill Red Lotus Blade immediately after Fast Blade will yield a type of skillchain known as Liquefaction.
        FURTHERMORE_ADDING_A_COMBO_AFTER_THE_LIQUEFACTION_EFFECT                  = 13549,  -- Furthermore, adding a Combo after the liquefaction effect will produce a more advanced Fusion skillchain.
        IN_THE_TAXONOMY_OF_SKILLCHAINS_EACH_TYPE_IS                               = 13550,  -- In the taxonomy of skillchains, each type is related to one or more specific elements. Liquefaction is bound to the element of fire, for example, and fusion to both fire and light.
        ANOTHER_CRUCIAL_POINT_WHICH_I_SIMPLY_CANNOT_EMPHASIZE                     = 13551,  -- Another crucial point, which I simply cannot emphasize enough, is the importance of timing in the execution of skillchains.
        ONE_MUST_NOT_BE_TOO_OVERZEALOUS_BUT_TOO                                   = 13552,  -- One must not be too overzealous, but too much patience can also be damning. It is most ideal to time the latter weapon skill to begin just a second or two after the preceding one is complete.
        THE_POSSIBLE_WEAPON_SKILL_SEQUENCES_AND_THE_DIFFERENT                     = 13553,  -- The possible weapon skill sequences and the different skillchains they yield are highly variegated. It is said of this time-tested battle art that it takes a moment to learn, and a lifetime to master.
        MAGIC_BURSTS_ARE_ANOTHER_TYPE_OF_SUPERNATURAL_PHENOMENA                   = 13554,  -- Magic bursts are another type of supernatural phenomena which occur after carefully selected and impeccably timed spells are cast following a skillchain. Such spells exceed their typical counterparts in that they are enhanced in both power and accuracy. You will commonly see magic bursts abbreviated as MB.
        MAGIC_BURSTS_WILL_NOT_TAKE_PLACE_IF_THE                                   = 13555,  -- Magic bursts will not take place if the element of the spell being cast does not match the element of the skillchain preceding it.
        TO_TAKE_AN_EXAMPLE_A_DETONATION_SKILLCHAIN_WHICH                          = 13556,  -- To take an example, a detonation skillchain, which has wind as its element, followed by an aero or other like spell, will generate a magic burst.
        IN_THE_SAME_VEIN_THUNDER_OR_ANY_COGNATE                                   = 13557,  -- In the same vein, thunder, or any cognate spell, would result in a magic burst should it follow an impaction skillchain, itself deriving power from that very element.
        AS_I_SAID_PREVIOUSLY_SOME_SKILLCHAINS_ARE_ASSOCIATED                      = 13558,  -- As I said previously, some skillchains are associated with more than one element. Take fragmentation, for example. It is composed of equal parts wind and thunder. So chasing a fragmentation skillchain with any type of aero or thunder spell would create a magic burst.
        THE_KEY_TO_MASTERING_MAGIC_BURSTS_LIES_IN                                 = 13559,  -- The key to mastering magic bursts lies in learning the elemental attributes of both the skillchains you create as well as the magic you wield. The rest is simply a matter of timing.
        FOR_YOUR_CONVENIENCE_I_WILL_GO_OVER_THE                                   = 13560,  -- For your convenience, I will go over the elemental attributes of all skillchain types. Pay close attention.
        LEVEL_1_SKILLCHAIN_ASSOCIATED_ELEMENT_TRANSFIXION_LIGHT_LIQUEFACTION      = 13561,  -- Level 1 Skillchain (Associated element): Transfixion (Light), Liquefaction (Fire), Detonation (Wind), Impaction (Thunder), Induration (Ice), Reverberation (Water), Scission (Earth), Compression (Darkness).
        LEVEL_2_SKILLCHAIN_ASSOCIATED_ELEMENTS_FUSION_LIGHT_FIRE                  = 13562,  -- Level 2 Skillchain (Associated elements): Fusion (Light/Fire), Fragmentation (Wind/Thunder), Distortion (Ice/Water), Gravitation (Earth/Darkness).
        LEVEL_3_SKILLCHAIN_ASSOCIATED_ELEMENTS_LIGHT_LIGHT_FIRE                   = 13563,  -- Level 3 Skillchain (Associated elements): Light (Light/Fire/Wind/Thunder), Darkness (Ice/Water/Earth/Darkness).
        KUPO_HO_HO_THE_STARLIGHT_CELEBRATION_IS_ONCE                              = 13564,  -- Kupo ho ho! The Starlight Celebration is once again upon us!
        WE_MOOGLES_HAVE_SPENT_MANY_A_SLEEPLESS_NIGHT                              = 13565,  -- We moogles have spent many a sleepless night preparing for this year's festivities, kupo. Be sure not to miss any of the exceptionally exciting events that are being held in and about town during this most joyous of seasons.
        OH_AND_THERE_S_ONE_THING_YOU_SIMPLY                                       = 13566,  -- Oh, and there's one thing you simply must know, kupo. Should you come by any gift tokens, bring them to me and I'll furnish you with gorgeous gifts in exchange!
        NOW_RUN_ALONG_AND_IMMERSE_YOURSELF_IN_THE                                 = 13567,  -- Now, run along and immerse yourself in the revelry, kupo!
        AH_YOU_VE_BROUGHT_HERE_THIS_IS_FOR                                        = 13568,  -- Ah, you've brought %! Here, this is for you!
        WOW_THAT_S_QUITE_A_FEW_GIFT_TOKENS                                        = 13569,  -- Wow! That's quite a few gift tokens you have there, kupo!
        IF_YOU_RE_INTERESTED_I_CAN_EXCHANGE_ALL                                   = 13570,  -- If you're interested, I can exchange all the tokens you have for a grand gift of galactic proportion, kupo! Well, perhaps that's exaggerating things a tad.
        OF_COURSE_IT_S_PERFECTLY_PERMISSIBLE_TO_USE                               = 13571,  -- Of course, it's perfectly permissible to use them one at time. The decision is entirely yours, kupo!
        HOW_MANY_TOKENS_WILL_YOU_EXCHANGE_THE_WHOLE                               = 13572,  -- How many tokens will you exchange? The whole kaboodle! I'm a miser. Just the one, please.
